                <div className="w-8 h-8 bg-violet-600 rounded-lg flex items-center justify-center shadow-[0_0_15px_rgba(124,58,237,0.5)]">
                    <Zap className="text-white w-5 h-5 fill-current" />
                </div>
                <div className="text-2xl font-extrabold text-white tracking-tight">Zentara</div>
            </div>

            {/* Desktop Nav */}
            <nav className="hidden md:flex items-center space-x-8">
                <a href="#features" onClick={(e) => scrollToSection(e, 'features')} className="text-slate-400 hover:text-white font-medium transition-colors text-sm cursor-pointer">Features</a>
                <a href="#pricing" onClick={(e) => scrollToSection(e, 'pricing')} className="text-slate-400 hover:text-white font-medium transition-colors text-sm cursor-pointer">Pricing</a>
                <a href="#faq" onClick={(e) => scrollToSection(e, 'faq')} className="text-slate-400 hover:text-white font-medium transition-colors text-sm cursor-pointer">FAQ</a>
                <button onClick={() => scrollToAuth('login')} className="text-slate-400 hover:text-white font-medium transition-colors text-sm">Login</button>
