                  className="bg-violet-600 hover:bg-violet-700 text-white px-5 py-2 rounded-lg font-bold transition-all shadow-lg shadow-violet-900/20 hover:shadow-violet-600/40 hover:-translate-y-0.5 text-sm"
                >
                  Start Free Trial
                </button>
