];

const ContentStudio: React.FC = () => {
  const { generateContent, repurposePost, generateImage, brandVoice, addPost, restrictedTerms, integrations } = useApp();
  const location = useLocation();
  const [coreMessage, setCoreMessage] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedPosts, setGeneratedPosts] = useState<SocialPost[]>([]);

  // Generation Settings
  const [selectedPlatforms, setSelectedPlatforms] = useState<Platform[]>(['Instagram', 'LinkedIn', 'Twitter']);
  const [selectedFormat, setSelectedFormat] = useState<ContentFormat>('Post');

  // Selection & Scheduling State
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [postsToSchedule, setPostsToSchedule] = useState<SocialPost[]>([]);
  const [scheduleDate, setScheduleDate] = useState('');

  // Repurpose State
  const [repurposeTargetId, setRepurposeTargetId] = useState<string | null>(null);
  const [repurposePlatform, setRepurposePlatform] = useState<Platform>('Instagram');
  const [repurposeFormat, setRepurposeFormat] = useState<ContentFormat>('Story');
  const [isRepurposing, setIsRepurposing] = useState(false);

  // Image Gen State
  const [generatingImageForId, setGeneratingImageForId] = useState<string | null>(null);

  // Handle incoming data from Beta Tester
  useEffect(() => {
    if (location.state) {
      const { coreMessage, platforms, format } = location.state as any;
      if (coreMessage) setCoreMessage(coreMessage);
      if (platforms) setSelectedPlatforms(platforms);
      if (format) setSelectedFormat(format);

      // Clear history so refresh doesn't keep resetting
      window.history.replaceState({}, document.title);
    }
  }, [location.state]);

  const togglePlatform = (p: Platform) => {
    setSelectedPlatforms(prev => 
      prev.includes(p) ? prev.filter(x => x !== p) : [...prev, p]
    );
  };

  const handleGenerate = async () => {
    if (!coreMessage.trim()) return;
    if (selectedPlatforms.length === 0) {
      alert("Select at least one platform.");
      return;
    }
    setIsGenerating(true);
    setSelectedIds([]);
    try {
      const posts = await generateContent(coreMessage, { platforms: selectedPlatforms, format: selectedFormat });
      setGeneratedPosts(posts);
    } catch (e) {
      console.error(e);
      alert("Failed to generate. Please check your connection.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleGenerateImage = async (post: SocialPost) => {
    if (!post.visualPrompt) return;
    setGeneratingImageForId(post.id);
    try {
        const imageUrl = await generateImage(post.visualPrompt);
        if (imageUrl) {
            setGeneratedPosts(prev => prev.map(p => 
                p.id === post.id ? { ...p, imageUrl } : p
            ));
        } else {
            alert("Failed to generate image. Try again.");
        }
    } catch (e) {
        console.error(e);
        alert("Error generating image.");
    } finally {
        setGeneratingImageForId(null);
    }
  };

  const handleRepurpose = async (originalPost: SocialPost) => {
    // Basic check to ensure target platform is connected
    const isConnected = integrations.some(i => i.connected && i.name.toLowerCase().includes(repurposePlatform.toLowerCase()));

    setIsRepurposing(true);
    try {
       const newPost = await repurposePost(originalPost, repurposePlatform, repurposeFormat);
       setGeneratedPosts(prev => [newPost, ...prev]);
       setRepurposeTargetId(null); // Close modal
    } catch (e) {
       alert("Failed to repurpose.");
    } finally {
       setIsRepurposing(false);
    }
  };

  const handleToggleSelect = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(pid => pid !== id) : [...prev, id]
    );
  };

  const handleSelectAll = () => {
    if (selectedIds.length === generatedPosts.length) {
      setSelectedIds([]);
    } else {
      setSelectedIds(generatedPosts.map(p => p.id));
    }
  };

  const openScheduleModal = (posts: SocialPost[]) => {
      setPostsToSchedule(posts);

      const tomorrow = new Date();
      tomorrow.setDate(tomorrow.getDate() + 1);
      tomorrow.setHours(9, 0, 0, 0);

      // Pad single digits for datetime-local input
      const pad = (n: number) => n.toString().padStart(2, '0');

      const year = tomorrow.getFullYear();
      const month = pad(tomorrow.getMonth() + 1);
      const day = pad(tomorrow.getDate());
      const hour = pad(tomorrow.getHours());
      const minute = pad(tomorrow.getMinutes());

      // Set local time string YYYY-MM-DDTHH:mm
      setScheduleDate(`${year}-${month}-${day}T${hour}:${minute}`);
  };

  const handleSingleAction = (post: SocialPost) => {
    if (post.flaggedKeywords.length > 0) {
      addPost(post);
      setGeneratedPosts(prev => prev.filter(p => p.id !== post.id));
      setSelectedIds(prev => prev.filter(id => id !== post.id));
      alert("Saved to Review Queue. This post has some quality flags.");
    } else {
      openScheduleModal([post]);
    }
  };

  const handleSaveDraft = (post: SocialPost) => {
    // addPost will handle status logic (Review if flagged, Draft if not)
    addPost({ ...post, status: PostStatus.DRAFT });
    setGeneratedPosts(prev => prev.filter(p => p.id !== post.id));
    setSelectedIds(prev => prev.filter(id => id !== post.id));
  };

  const handleBulkSchedule = () => {
    const selected = generatedPosts.filter(p => selectedIds.includes(p.id));
    if (selected.length === 0) return;
    openScheduleModal(selected);
  };

  const handleConfirmSchedule = () => {
    if (postsToSchedule.length === 0) return;

    if (!scheduleDate) {
      alert("Please select a date and time.");
      return;
    }

    const timestamp = new Date(scheduleDate).getTime();
    let scheduledCount = 0;
    let flaggedCount = 0;

    postsToSchedule.forEach(post => {
        // Check for flags here to provide accurate feedback
        const isFlagged = restrictedTerms.some(term => post.content.toLowerCase().includes(term.toLowerCase()));

        // addPost handles the actual status setting (Scheduled vs Needs Review)
        addPost({
            ...post,
            status: PostStatus.SCHEDULED,
            scheduledTime: timestamp
        });

        if (isFlagged) {
            flaggedCount++;
        } else {
            scheduledCount++;
        }
    });

    if (flaggedCount > 0) {
        alert(`${scheduledCount} posts scheduled. ${flaggedCount} posts flagged for review due to restricted terms.`);
    } else if (scheduledCount > 1) {
        // Optional success message for bulk actions
    }

    const scheduledIds = postsToSchedule.map(p => p.id);
    setGeneratedPosts(prev => prev.filter(p => !scheduledIds.includes(p.id)));
    setSelectedIds(prev => prev.filter(id => !scheduledIds.includes(id)));

    setPostsToSchedule([]);
    setScheduleDate('');
  };

  // Find the post being repurposed to provide recommendations
  const targetPost = generatedPosts.find(p => p.id === repurposeTargetId);

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col space-y-6 relative">
      {/* Scheduling Modal */}
      {postsToSchedule.length > 0 && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4">
           <div className="bg-slate-950 border border-slate-700 rounded-xl p-6 w-full max-w-md shadow-2xl max-h-[90vh] overflow-y-auto">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold text-white flex items-center gap-2">
                  <Calendar className="w-5 h-5 text-blue-500" />
                  Schedule {postsToSchedule.length} Post{postsToSchedule.length > 1 ? 's' : ''}
                </h3>
                <button onClick={() => setPostsToSchedule([])} className="text-slate-400 hover:text-white">
                  <X className="w-5 h-5" />
                </button>
              </div>

              <div className="mb-4">
                <p className="text-xs text-slate-500 uppercase font-bold mb-2">Selected Platforms</p>
                <div className="flex flex-wrap gap-2">
                  {postsToSchedule.map(p => (
                     <span key={p.id} className="text-xs bg-slate-900 border border-slate-700 px-2 py-1 rounded text-slate-300">
                       {p.platform}
                     </span>
                  ))}
                </div>
              </div>

              <div className="mb-6">
                <p className="text-sm text-slate-400 mb-2">When should {postsToSchedule.length > 1 ? 'these go' : 'this go'} live?</p>
                <input 
                  type="datetime-local"
                  className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-600 focus:outline-none"
                  value={scheduleDate}
                  onChange={(e) => setScheduleDate(e.target.value)}
                />
              </div>
              <div className="flex justify-end gap-3">
                <button onClick={() => setPostsToSchedule([])} className="px-4 py-2 text-slate-400 hover:text-white">Cancel</button>
                <button onClick={handleConfirmSchedule} className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-bold">Confirm</button>
              </div>
           </div>
        </div>
      )}

      {/* Repurpose Modal */}
      {repurposeTargetId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4">
           <div className="bg-slate-950 border border-slate-700 rounded-xl p-6 w-full max-w-3xl shadow-2xl max-h-[90vh] overflow-y-auto">
              <div className="flex justify-between items-center mb-6">
                 <h3 className="text-xl font-bold text-white flex items-center gap-2">
                    <RefreshCw className="w-5 h-5 text-blue-500" />
                    Repurpose Content
                 </h3>
                 <button onClick={() => setRepurposeTargetId(null)} className="text-slate-400 hover:text-white">
                    <X className="w-5 h-5" />
                 </button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">
                 {/* Platform Selection */}
                 <div>
                    <div className="flex justify-between items-center mb-3">
                        <label className="text-xs text-slate-500 uppercase font-bold tracking-wider">Target Platform</label>
                        <span className="text-[10px] text-slate-500 bg-slate-900 px-2 py-0.5 rounded border border-slate-800">Only connected accounts</span>
                    </div>
                    <div className="grid grid-cols-3 gap-3">
                       {PLATFORMS.map(p => {
                          // Check if platform is connected
                          const isConnected = integrations.some(i => 
                              i.connected && i.name.toLowerCase().includes(p.id.toLowerCase())
                          );

                          // Recommendation Logic
                          let isRecommended = false;
                          if (targetPost) {
                              if (targetPost.platform === 'Instagram' && (p.id === 'Pinterest' || p.id === 'Facebook')) isRecommended = true;
                              if (targetPost.platform === 'LinkedIn' && (p.id === 'Twitter' || p.id === 'Threads')) isRecommended = true;
                              if (targetPost.platform === 'Twitter' && (p.id === 'LinkedIn' || p.id === 'Threads')) isRecommended = true;
                              if (targetPost.platform === 'TikTok' && (p.id === 'YouTube' || p.id === 'Instagram')) isRecommended = true;
                          }

                          return (
                            <button 
                                key={p.id}
                                onClick={() => isConnected && setRepurposePlatform(p.id)}
                                disabled={!isConnected}
                                className={clsx(
                                "relative flex flex-col items-center justify-center p-3 rounded-xl border-2 transition-all gap-2 h-28 group",
                                isConnected && repurposePlatform === p.id 
                                    ? "bg-blue-600/10 border-blue-500 text-white shadow-lg shadow-blue-500/20" 
                                    : isConnected
                                    ? "bg-slate-900 border-slate-800 text-slate-400 hover:border-slate-600 hover:bg-slate-800"
                                    : "bg-slate-950 border-slate-800/50 text-slate-700 cursor-not-allowed opacity-60"
                                )}
                                title={!isConnected ? "Connect in Settings" : p.label}
                            >
                                {isRecommended && isConnected && (
                                    <span className="absolute -top-2.5 left-1/2 -translate-x-1/2 bg-emerald-500 text-white text-[9px] font-bold px-2 py-0.5 rounded-full shadow-md border border-slate-900 whitespace-nowrap z-10">
                                        Recommended
                                    </span>
                                )}
                                {isConnected && repurposePlatform === p.id && (
                                    <div className="absolute top-2 right-2 w-4 h-4 bg-blue-500 rounded-full flex items-center justify-center animate-in zoom-in">
                                        <CheckCircle className="w-3 h-3 text-white" />
                                    </div>
                                )}
                                {!isConnected && (
                                    <div className="absolute top-2 right-2">
                                        <Lock className="w-3 h-3 text-slate-600" />
                                    </div>
                                )}
                                {p.icon && <p.icon className={clsx("w-8 h-8 transition-transform", isConnected && "group-hover:scale-110", isConnected && repurposePlatform === p.id ? "text-blue-400" : isConnected ? p.color : "text-slate-700")} />}
                                <span className="text-xs font-bold text-center leading-tight">{p.label.split('(')[0]}</span>
                            </button>
                          );
                       })}
                    </div>
                 </div>

                 {/* Format Selection */}
                 <div>
                    <label className="text-xs text-slate-500 uppercase font-bold tracking-wider mb-3 block">New Format</label>
                    <div className="grid grid-cols-2 gap-3">
                       {FORMATS.map(f => (
                          <button 
                              key={f.id}
                              onClick={() => setRepurposeFormat(f.id)}
                              className={clsx(
                                "relative flex flex-col items-start p-4 rounded-xl border-2 transition-all gap-2 h-24 group text-left",
                                repurposeFormat === f.id 
                                  ? "bg-purple-600/10 border-purple-500 text-white shadow-lg shadow-purple-500/20" 
                                  : "bg-slate-900 border-slate-800 text-slate-400 hover:border-slate-600 hover:bg-slate-800"
                              )}
                           >
                              <div className="flex justify-between w-full">
                                  <div className={clsx("p-1.5 rounded-lg transition-colors", repurposeFormat === f.id ? "bg-purple-500/20 text-purple-400" : "bg-slate-800 text-slate-500")}>
                                    <f.icon className="w-5 h-5" />
                                  </div>
                                  {repurposeFormat === f.id && (
                                    <CheckCircle className="w-4 h-4 text-purple-500 animate-in zoom-in" />
                                  )}
                              </div>
                              <div>
                                  <span className="text-sm font-bold block">{f.label}</span>
                                  <span className="text-[10px] text-slate-500 font-medium">Auto-adapted</span>
                              </div>
                           </button>
                       ))}
                    </div>
                 </div>
              </div>

              <div className="flex justify-end gap-3 pt-6 border-t border-slate-800">
                 <button onClick={() => setRepurposeTargetId(null)} className="px-5 py-2.5 text-slate-400 hover:text-white text-sm font-medium transition-colors">Cancel</button>
                 <button 
                   onClick={() => handleRepurpose(generatedPosts.find(p => p.id === repurposeTargetId)!)}
                   disabled={isRepurposing}
                   className="bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 text-white px-8 py-2.5 rounded-lg text-sm font-bold flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20 transform active:scale-95"
                 >
                    {isRepurposing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
                    Generate Remix
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* Steps Indicator */}
      <div className="w-full bg-slate-950 border border-slate-800 rounded-lg p-4 mb-2 overflow-x-auto shrink-0">
        <div className="flex items-center justify-between min-w-[300px] max-w-3xl mx-auto relative">
           {/* Connecting Line */}
           <div className="absolute top-1/2 left-0 w-full h-0.5 bg-slate-800 -z-10"></div>

           {/* Step 1 */}
           <div className="bg-slate-950 px-4 flex flex-col items-center gap-1 z-10">
              <div className="w-8 h-8 rounded-full bg-blue-600 text-white flex items-center justify-center font-bold text-sm shadow-[0_0_10px_rgba(37,99,235,0.5)]">1</div>
              <span className="text-xs font-bold text-blue-400 whitespace-nowrap">Topic & Settings</span>
           </div>

           {/* Step 2 */}
           <div className="bg-slate-950 px-4 flex flex-col items-center gap-1 z-10">
              <div className={clsx(
                "w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm transition-all duration-500",
                generatedPosts.length > 0 ? "bg-blue-600 text-white shadow-[0_0_10px_rgba(37,99,235,0.5)]" : "bg-slate-800 text-slate-500 border border-slate-700"
              )}>2</div>
              <span className={clsx("text-xs font-bold transition-colors whitespace-nowrap", generatedPosts.length > 0 ? "text-blue-400" : "text-slate-500")}>Review Content</span>
           </div>

           {/* Step 3 */}
           <div className="bg-slate-950 px-4 flex flex-col items-center gap-1 z-10">
              <div className={clsx(
                "w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm transition-all duration-500",
                selectedIds.length > 0 ? "bg-blue-600 text-white shadow-[0_0_10px_rgba(37,99,235,0.5)]" : "bg-slate-800 text-slate-500 border border-slate-700"
              )}>3</div>
              <span className={clsx("text-xs font-bold transition-colors whitespace-nowrap", selectedIds.length > 0 ? "text-blue-400" : "text-slate-500")}>Schedule</span>
           </div>
        </div>
      </div>

      <div className="flex justify-between items-center shrink-0">
        <div>
           <h2 className="text-2xl md:text-3xl font-bold text-white">Create Post</h2>
           <p className="text-slate-400 text-sm md:text-base">Multi-channel content creation powered by AI.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 h-full min-h-0">
        {/* Left Config Panel */}
        <div className="lg:col-span-4 h-full overflow-y-auto pr-2 pb-10">
          <div className="bg-slate-950 border border-slate-800 rounded-xl p-5">
             <div className="mb-4">
                <label className="block text-sm font-bold text-slate-200 mb-1">Topic / Idea</label>
                <textarea
                  className="w-full h-32 bg-slate-900 border border-slate-800 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-600 focus:outline-none resize-none placeholder-slate-600 text-sm"
                  placeholder="e.g. We have a special on croissants this weekend! Buy one get one free."
                  value={coreMessage}
                  onChange={(e) => setCoreMessage(e.target.value)}
                />
             </div>

             <div className="mb-6">
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Target Platforms</label>
                <div className="grid grid-cols-5 gap-2">
                   {PLATFORMS.map(p => {
                      const Icon = p.icon;
                      const isSelected = selectedPlatforms.includes(p.id);
                      return (
                        <button
                          key={p.id}
                          onClick={() => togglePlatform(p.id)}
                          className={clsx(
                             "w-10 h-10 rounded-lg flex items-center justify-center border transition-all mx-auto",
                             isSelected 
                               ? `bg-slate-800 border-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.2)]` 
                               : "bg-slate-900 border-slate-800 opacity-60 hover:opacity-100 hover:border-slate-600"
                          )}
                          title={p.label}
                        >
                           {Icon ? <Icon className={clsx("w-5 h-5", isSelected ? p.color : "text-slate-400")} /> : <span className={clsx("text-xs font-bold", isSelected ? p.color : "text-slate-400")}>{p.label[0]}</span>}
                        </button>
                      );
                   })}
                </div>
             </div>

             <div className="mb-6">
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Format</label>
                <select 
                   className="w-full bg-slate-900 border border-slate-800 rounded-lg p-2.5 text-white focus:ring-2 focus:ring-blue-600 outline-none"
                   value={selectedFormat}
                   onChange={(e) => setSelectedFormat(e.target.value as ContentFormat)}
                >
                   {FORMATS.map(f => (
                      <option key={f.id} value={f.id}>{f.label}</option>
                   ))}
                </select>
             </div>

             <div className="flex items-center gap-2 mb-6 p-3 bg-slate-900/50 rounded-lg border border-slate-800">
                <div className="w-2 h-2 rounded-full bg-green-500"></div>
                <div className="flex-1">
                   <p className="text-xs font-bold text-slate-300">Brand Voice Active</p>
                   <p className="text-[10px] text-slate-500 truncate">{brandVoice.name}</p>
                </div>
             </div>

             <button
                onClick={handleGenerate}
                disabled={isGenerating || !coreMessage}
                className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-slate-800 disabled:text-slate-500 text-white px-6 py-3 rounded-lg font-bold flex items-center justify-center gap-2 transition-all shadow-lg shadow-blue-900/20"
               >
                 {isGenerating ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
                 Generate Content
             </button>
          </div>
        </div>

        {/* Results Panel */}
        <div className="lg:col-span-8 space-y-4 h-full overflow-y-auto pb-20 pr-2">
          {generatedPosts.length === 0 && !isGenerating && (
            <div className="h-full flex flex-col items-center justify-center text-slate-600 border-2 border-dashed border-slate-800 rounded-xl min-h-[400px]">
              <div className="p-4 bg-slate-900 rounded-full mb-4">
                 <Sparkles className="w-8 h-8 text-blue-900" />
              </div>
              <h3 className="text-lg font-bold text-slate-400 mb-2">Ready to create magic?</h3>
              <p className="text-sm max-w-xs text-center">Select your target platforms on the left and hit Generate to see the AI in action.</p>
            </div>
          )}

          {isGenerating && (
            <div className="space-y-4">
              {[1, 2].map(i => (
                <div key={i} className="animate-pulse bg-slate-950 border border-slate-800 rounded-xl p-6 h-48"></div>
              ))}
            </div>
          )}

          {generatedPosts.length > 0 && (
             <div className="flex items-center justify-between bg-slate-900/50 border border-slate-800 rounded-lg p-3 sticky top-0 z-10 backdrop-blur-md">
                <div className="flex items-center gap-3">
                    <input 
                        type="checkbox"
                        checked={selectedIds.length > 0 && selectedIds.length === generatedPosts.length}
                        onChange={handleSelectAll}
                        className="w-5 h-5 rounded border-slate-700 bg-slate-950 text-blue-600 focus:ring-blue-500 cursor-pointer"
                    />
                    <span className="text-sm font-medium text-slate-400">
                        {selectedIds.length > 0 ? `${selectedIds.length} Selected` : 'Select All'}
                    </span>
                </div>
                {selectedIds.length > 0 && (
                    <button 
                        onClick={handleBulkSchedule}
                        className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-1.5 rounded-lg text-sm font-medium transition-colors flex items-center gap-2 shadow-lg shadow-blue-900/20"
                    >
                        <Calendar className="w-4 h-4" />
                        Schedule ({selectedIds.length})
                    </button>
                )}
             </div>
          )}

          {generatedPosts.map((post) => (
            <div key={post.id} className="bg-slate-950 border border-slate-800 rounded-xl p-6 group hover:border-slate-700 transition-all relative">
              <div className="absolute top-6 left-6">
                 <input 
                    type="checkbox"
                    checked={selectedIds.includes(post.id)}
                    onChange={() => handleToggleSelect(post.id)}
                    className="w-5 h-5 rounded border-slate-700 bg-slate-900 text-blue-600 focus:ring-blue-500 cursor-pointer"
                 />
              </div>

              <div className="flex justify-between items-start mb-4 pl-8">
                <div className="flex items-center gap-2">
                   <span className={clsx(
                     "px-2 py-1 rounded text-xs font-bold uppercase tracking-wider",
                     PLATFORMS.find(p => p.id === post.platform)?.color.replace('text-', 'bg-').replace('600', '900').replace('500', '900').replace('400', '900') + " bg-opacity-30 " + PLATFORMS.find(p => p.id === post.platform)?.color.replace('text-', 'text-')
                   )}>
                     {post.platform}
                   </span>
                   <span className="px-2 py-1 rounded text-xs font-bold uppercase tracking-wider bg-slate-800 text-slate-400">
                     {post.format || 'Post'}
                   </span>
                </div>

                <div className="flex items-center gap-2">
                    <button 
