  // Helper to determine recommended formats based on platform
  const getRecommendedFormats = (platform: Platform): ContentFormat[] => {
      switch(platform) {
          case 'Instagram': return ['Reel', 'Story', 'Carousel'];
          case 'TikTok': return ['Reel'];
          case 'YouTube': return ['Video', 'Reel'];
          case 'LinkedIn': return ['Post', 'Carousel'];
          case 'Twitter': 
          case 'Twitter (X)': return ['Post', 'Thread'];
          case 'Pinterest': return ['Post'];
          case 'Facebook': return ['Post', 'Reel', 'Story'];
          case 'Threads': return ['Thread', 'Post'];
          default: return ['Post'];
      }
  };

  // Find the post being repurposed to provide recommendations
  const targetPost = generatedPosts.find(p => p.id === repurposeTargetId);

  // Calculate format recommendations based on selected platform
  const recommendedFormats = getRecommendedFormats(repurposePlatform);

