                                rows={3}
                                placeholder="Describe the image you want..."
                            />

                            <button
                                onClick={() => handleGenerateImage(post)}
                                disabled={generatingImageForId === post.id}
                                className={clsx(
                                    "w-full text-white text-xs py-2.5 rounded-lg border transition-all flex items-center justify-center gap-2 font-bold shadow-lg relative z-10",
                                    generatingImageForId === post.id 
                                        ? "bg-slate-800 border-slate-700 text-slate-400 cursor-not-allowed" 
                                        : "bg-gradient-to-r from-purple-600 to-blue-600 hover:from-purple-500 hover:to-blue-500 border-transparent shadow-purple-900/20 active:scale-[0.98]"
                                )}
                            >
                                {generatingImageForId === post.id ? (
                                    <>
                                        <Loader2 className="w-4 h-4 animate-spin" /> Creating Visual...
                                    </>
                                ) : (
                                    <>
                                        <Wand2 className="w-4 h-4 animate-pulse" /> Visualize with AI
                                    </>
                                )}
                            </button>
                        </div>
                    )}

                    {post.flaggedKeywords.length > 0 && (
                        <div className="p-3 bg-amber-900/10 border border-amber-900/30 rounded-lg flex items-start gap-2">
                            <AlertTriangle className="w-4 h-4 text-amber-500 shrink-0 mt-0.5" />
                            <div>
                                <p className="text-xs font-bold text-amber-400">Quality Check</p>
                                <p className="text-[10px] text-amber-300/80">
                                Contains: {post.flaggedKeywords.join(', ')}
                                </p>
                            </div>
                        </div>
                    )}
                 </div>
              </div>

              <div className="flex flex-wrap justify-end gap-3 pt-4 border-t border-slate-900 pl-8 mt-4">
                <button 
                  onClick={() => navigator.clipboard.writeText(post.content)}
                  className="p-2 text-slate-500 hover:text-white transition-colors"
                  title="Copy text"
                >
                  <Copy className="w-5 h-5" />
                </button>
                <button 
                  onClick={() => handleSaveDraft(post)}
                  className="bg-slate-900 border border-slate-800 hover:bg-slate-800 text-slate-300 px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"
                >
                  <Save className="w-4 h-4" />
                  Save Draft
                </button>
                <button 
                  onClick={() => handleSingleAction(post)}
                  className="bg-slate-800 hover:bg-slate-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"
                >
                  <Calendar className="w-4 h-4 text-blue-500" />
                  Schedule
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

