      const scale = size === 'lg' ? 1.5 : 1;
      const style = { transform: `scale(${scale})` };

      switch(id) {
          case 'Post': 
            return <div className={clsx("w-8 h-8 border-2 rounded-md transition-colors", colorClass)} style={style}></div>;
          case 'Story':
          case 'Reel':
            return <div className={clsx("w-6 h-10 border-2 rounded-md transition-colors", colorClass)} style={style}></div>;
          case 'Video':
            return <div className={clsx("w-10 h-6 border-2 rounded-md transition-colors flex items-center justify-center", colorClass)} style={style}><Play className="w-3 h-3 fill-current opacity-50" /></div>;
          case 'Carousel':
            return <div className="flex gap-0.5 items-center" style={style}>
                <div className={clsx("w-6 h-8 border-2 rounded-sm opacity-40 scale-90", colorClass)}></div>
                <div className={clsx("w-6 h-8 border-2 rounded-sm z-10", colorClass)}></div>
                <div className={clsx("w-6 h-8 border-2 rounded-sm opacity-40 scale-90", colorClass)}></div>
            </div>;
          case 'Thread':
            return <div className="flex flex-col gap-1 items-center" style={style}>
                <div className={clsx("w-8 h-2 border rounded-full", colorClass)}></div>
                <div className={clsx("w-0.5 h-2 bg-current opacity-50", isSelected ? "text-white" : "text-slate-600")}></div>
                <div className={clsx("w-8 h-2 border rounded-full", colorClass)}></div>
            </div>;
          default: 
            return <div className={clsx("w-8 h-8 border-2 rounded-full", colorClass)} style={style}></div>;
      }
  }

  // Helper to determine recommended formats based on platform
  const getRecommendedFormats = (platform: Platform): ContentFormat[] => {
      switch(platform) {
          case 'Instagram': return ['Reel', 'Story', 'Carousel'];
          case 'TikTok': return ['Reel'];
          case 'YouTube': return ['Video', 'Reel'];
          case 'LinkedIn': return ['Post', 'Carousel'];
          case 'Twitter': 
          case 'Twitter (X)': return ['Post', 'Thread'];
          case 'Pinterest': return ['Post'];
          case 'Facebook': return ['Post', 'Reel', 'Story'];
          case 'Threads': return ['Thread', 'Post'];
          default: return ['Post'];
      }
  };

  // Find the post being repurposed to provide recommendations
  const targetPost = generatedPosts.find(p => p.id === repurposeTargetId);
  const recommendedFormats = getRecommendedFormats(repurposePlatform);

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col space-y-6 relative">
      {/* Scheduling Modal */}
      {postsToSchedule.length > 0 && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4">
           <div className="bg-slate-950 border border-slate-700 rounded-xl p-6 w-full max-w-md shadow-2xl max-h-[90vh] overflow-y-auto">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold text-white flex items-center gap-2">
                  <Calendar className="w-5 h-5 text-blue-500" />
                  Schedule {postsToSchedule.length} Post{postsToSchedule.length > 1 ? 's' : ''}
                </h3>
                <button onClick={() => setPostsToSchedule([])} className="text-slate-400 hover:text-white">
                  <X className="w-5 h-5" />
                </button>
              </div>

              <div className="mb-4">
                <p className="text-xs text-slate-500 uppercase font-bold mb-2">Selected Platforms</p>
                <div className="flex flex-wrap gap-2">
                  {postsToSchedule.map(p => (
                     <span key={p.id} className="text-xs bg-slate-900 border border-slate-700 px-2 py-1 rounded text-slate-300">
                       {p.platform}
                     </span>
                  ))}
                </div>
              </div>

              <div className="mb-6">
                <p className="text-sm text-slate-400 mb-2">When should {postsToSchedule.length > 1 ? 'these go' : 'this go'} live?</p>
                <input 
                  type="datetime-local"
                  className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-600 focus:outline-none"
                  value={scheduleDate}
                  onChange={(e) => setScheduleDate(e.target.value)}
                />
              </div>
              <div className="flex justify-end gap-3">
                <button onClick={() => setPostsToSchedule([])} className="px-4 py-2 text-slate-400 hover:text-white">Cancel</button>
                <button onClick={handleConfirmSchedule} className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-bold">Confirm</button>
              </div>
           </div>
        </div>
      )}

      {/* Repurpose Modal */}
      {repurposeTargetId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4">
           <div className="bg-slate-950 border border-slate-700 rounded-xl p-6 w-full max-w-3xl shadow-2xl max-h-[90vh] overflow-y-auto">
              <div className="flex justify-between items-center mb-6">
                 <div>
                    <h3 className="text-xl font-bold text-white flex items-center gap-2">
                        <RefreshCw className="w-6 h-6 text-blue-500" />
                        Repurpose Content
                    </h3>
                    <p className="text-sm text-slate-400 mt-1">Transform your existing post into a native format for another channel.</p>
                 </div>
                 <button onClick={() => setRepurposeTargetId(null)} className="text-slate-400 hover:text-white bg-slate-900 p-2 rounded-full hover:bg-slate-800">
                    <X className="w-5 h-5" />
                 </button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">
                 {/* Platform Selection */}
                 <div>
                    <div className="flex justify-between items-center mb-3">
                        <label className="text-xs text-slate-400 uppercase font-bold tracking-wider">1. Choose Destination</label>
                        <span className="text-[10px] text-slate-500 bg-slate-900 px-2 py-0.5 rounded border border-slate-800">Only connected accounts</span>
                    </div>
                    <div className="grid grid-cols-3 gap-3">
                       {PLATFORMS.map(p => {
                          // Check if platform is connected
                          const isConnected = integrations.some(i => 
                              i.connected && i.name.toLowerCase().includes(p.id.toLowerCase())
                          );

                          // Recommendation Logic
                          let isRecommended = false;
                          if (targetPost) {
                              if (targetPost.platform === 'Instagram' && (p.id === 'Pinterest' || p.id === 'Facebook')) isRecommended = true;
                              if (targetPost.platform === 'LinkedIn' && (p.id === 'Twitter' || p.id === 'Threads')) isRecommended = true;
                              if (targetPost.platform === 'Twitter' && (p.id === 'LinkedIn' || p.id === 'Threads')) isRecommended = true;
                              if (targetPost.platform === 'TikTok' && (p.id === 'YouTube' || p.id === 'Instagram')) isRecommended = true;
                          }

                          const isSelected = isConnected && repurposePlatform === p.id;

                          return (
                            <button 
                                key={p.id}
                                onClick={() => isConnected && setRepurposePlatform(p.id)}
                                disabled={!isConnected}
                                className={clsx(
                                "relative flex flex-col items-center justify-center p-3 rounded-xl border-2 transition-all gap-3 h-32 group",
                                isSelected 
                                    ? "border-blue-500 bg-blue-500/10 text-white shadow-[0_0_20px_rgba(59,130,246,0.3)] scale-105 z-10" 
                                    : isConnected
                                    ? "bg-slate-900 border-slate-800 text-slate-400 hover:border-slate-600 hover:bg-slate-800"
                                    : "bg-slate-950 border-slate-800/50 text-slate-700 cursor-not-allowed opacity-60 grayscale"
                                )}
                                title={!isConnected ? "Connect in Settings" : p.label}
                            >
                                {isRecommended && isConnected && !isSelected && (
                                    <span className="absolute -top-2.5 left-1/2 -translate-x-1/2 bg-emerald-600 text-white text-[9px] font-bold px-2 py-0.5 rounded-full shadow-md border border-slate-900 whitespace-nowrap z-10">
                                        Recommended
                                    </span>
                                )}
                                {isSelected && (
                                    <div className="absolute top-2 right-2 w-5 h-5 bg-blue-500 rounded-full flex items-center justify-center animate-in zoom-in">
                                        <CheckCircle className="w-3 h-3 text-white" />
                                    </div>
                                )}
                                {!isConnected && (
                                    <div className="absolute top-2 right-2">
                                        <Lock className="w-3 h-3 text-slate-600" />
                                    </div>
                                )}
                                {p.icon && <p.icon className={clsx("w-10 h-10 transition-transform duration-300", isSelected ? "scale-110 text-blue-400" : isConnected ? "group-hover:scale-110 " + p.color : "text-slate-600")} />}
                                <span className={clsx("text-xs font-bold text-center leading-tight", isSelected ? "text-white" : "text-slate-400")}>{p.label.split('(')[0]}</span>
                            </button>
                          );
                       })}
                    </div>
                 </div>

                 {/* Format Selection */}
                 <div>
                    <label className="text-xs text-slate-400 uppercase font-bold tracking-wider mb-3 block">2. Choose Style</label>
                    <div className="grid grid-cols-2 gap-3">
                       {FORMATS.map(f => {
                          const isSelected = repurposeFormat === f.id;
                          const isRecommended = recommendedFormats.includes(f.id);
                          return (
                            <button 
                                key={f.id}
                                onClick={() => setRepurposeFormat(f.id)}
                                className={clsx(
                                    "relative flex flex-col items-center justify-center p-4 rounded-xl border-2 transition-all gap-3 h-32 group text-center",
                                    isSelected 
                                    ? "bg-purple-500/10 border-purple-500 text-white shadow-[0_0_20px_rgba(168,85,247,0.3)] scale-105 z-10" 
                                    : "bg-slate-900 border-slate-800 text-slate-400 hover:border-slate-600 hover:bg-slate-800"
                                )}
                            >
                                {isRecommended && !isSelected && (
                                    <span className="absolute -top-2 right-2 bg-emerald-600 text-white text-[9px] font-bold px-2 py-0.5 rounded-full shadow-md z-10 border border-slate-900">
                                        Recommended
                                    </span>
                                )}
                                <div className={clsx("shrink-0 flex items-center justify-center w-16 h-16 rounded-lg transition-colors bg-slate-950/50", isSelected ? "border border-purple-500/50" : "border border-slate-700")}>
                                    {renderFormatShape(f.id, isSelected, 'lg')}
                                </div>
                                <div className="min-w-0">
                                    <span className={clsx("text-sm font-bold block", isSelected ? "text-white" : "text-slate-300")}>{f.label}</span>
                                </div>
                                {isSelected && (
                                    <div className="absolute top-2 right-2">
                                        <CheckCircle className="w-5 h-5 text-purple-500 animate-in zoom-in" />
                                    </div>
                                )}
                            </button>
                          );
                       })}
                    </div>
                 </div>
              </div>

              <div className="flex justify-end gap-3 pt-6 border-t border-slate-800">
                 <button onClick={() => setRepurposeTargetId(null)} className="px-5 py-2.5 text-slate-400 hover:text-white text-sm font-medium transition-colors">Cancel</button>
                 <button 
                   onClick={() => handleRepurpose(generatedPosts.find(p => p.id === repurposeTargetId)!)}
                   disabled={isRepurposing}
                   className="bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 text-white px-8 py-3 rounded-xl text-sm font-bold flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20 transform active:scale-95 ring-1 ring-white/10"
                 >
                    {isRepurposing ? <Loader2 className="w-5 h-5 animate-spin" /> : <RefreshCw className="w-5 h-5" />}
                    Generate Remix
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* Steps Indicator */}
      <div className="w-full bg-slate-950 border border-slate-800 rounded-lg p-4 mb-2 overflow-x-auto shrink-0">
        <div className="flex items-center justify-between min-w-[300px] max-w-3xl mx-auto relative">
           {/* Connecting Line */}
           <div className="absolute top-1/2 left-0 w-full h-0.5 bg-slate-800 -z-10"></div>

           {/* Step 1 */}
           <div className="bg-slate-950 px-4 flex flex-col items-center gap-1 z-10">
              <div className="w-8 h-8 rounded-full bg-blue-600 text-white flex items-center justify-center font-bold text-sm shadow-[0_0_10px_rgba(37,99,235,0.5)]">1</div>
              <span className="text-xs font-bold text-blue-400 whitespace-nowrap">Topic & Settings</span>
           </div>

           {/* Step 2 */}
           <div className="bg-slate-950 px-4 flex flex-col items-center gap-1 z-10">
              <div className={clsx(
                "w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm transition-all duration-500",
                generatedPosts.length > 0 ? "bg-blue-600 text-white shadow-[0_0_10px_rgba(37,99,235,0.5)]" : "bg-slate-800 text-slate-500 border border-slate-700"
              )}>2</div>
              <span className={clsx("text-xs font-bold transition-colors whitespace-nowrap", generatedPosts.length > 0 ? "text-blue-400" : "text-slate-500")}>Review Content</span>
           </div>

           {/* Step 3 */}
           <div className="bg-slate-950 px-4 flex flex-col items-center gap-1 z-10">
              <div className={clsx(
                "w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm transition-all duration-500",
                selectedIds.length > 0 ? "bg-blue-600 text-white shadow-[0_0_10px_rgba(37,99,235,0.5)]" : "bg-slate-800 text-slate-500 border border-slate-700"
              )}>3</div>
              <span className={clsx("text-xs font-bold transition-colors whitespace-nowrap", selectedIds.length > 0 ? "text-blue-400" : "text-slate-500")}>Schedule</span>
           </div>
        </div>
      </div>

      <div className="flex justify-between items-center shrink-0">
        <div>
           <h2 className="text-2xl md:text-3xl font-bold text-white">Create Post</h2>
           <p className="text-slate-400 text-sm md:text-base">Turn a simple idea into posts for all your channels.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 h-full min-h-0">
        {/* Left Config Panel */}
        <div className="lg:col-span-4 h-full overflow-y-auto pr-2 pb-10">
          <div className="bg-slate-950 border border-slate-800 rounded-xl p-5">
             <div className="mb-6">
                <label className="block text-sm font-bold text-slate-200 mb-3 flex items-center gap-2">
                    <Lightbulb className="w-4 h-4 text-yellow-400" /> What do you want to post about?
                </label>

                {/* Categorized Idea Starters */}
                <div className="space-y-2 mb-4">
                    {Object.entries(CATEGORIZED_IDEAS).map(([category, ideas]) => (
                        <div key={category} className="flex flex-wrap gap-2">
                            <span className="text-[10px] font-bold text-slate-500 uppercase tracking-wider w-full">{category}</span>
                            {ideas.map(idea => (
                                <button 
                                    key={idea} 
                                    onClick={() => setCoreMessage(prev => prev ? prev + " " + idea : idea)}
                                    className="text-[10px] bg-slate-900 hover:bg-slate-800 border border-slate-800 hover:border-slate-600 text-slate-300 px-3 py-1.5 rounded-lg transition-colors shadow-sm"
                                >
                                    {idea}
                                </button>
                            ))}
                        </div>
                    ))}
                </div>

                <textarea
                  className="w-full h-32 bg-slate-900 border border-slate-800 rounded-xl p-4 text-white focus:ring-2 focus:ring-blue-600 focus:outline-none resize-none placeholder-slate-600 text-sm leading-relaxed"
                  placeholder="e.g. We have a special on croissants this weekend! Buy one get one free. #weekendvibes"
                  value={coreMessage}
                  onChange={(e) => setCoreMessage(e.target.value)}
                />
             </div>

             <div className="mb-6">
                <div className="flex justify-between items-center mb-3">
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider">Target Platforms</label>
                    <button 
                        onClick={handleSelectAllPlatforms}
                        className="text-[10px] text-blue-400 hover:text-blue-300 font-bold uppercase tracking-wider flex items-center gap-1 bg-blue-900/10 px-2 py-1 rounded hover:bg-blue-900/20"
                    >
                        <Layers className="w-3 h-3" />
                        {selectedPlatforms.length === PLATFORMS.length ? 'Deselect All' : 'Select All'}
                    </button>
                </div>
                <div className="grid grid-cols-3 gap-2">
                   {PLATFORMS.map(p => {
                      const Icon = p.icon;
                      const isSelected = selectedPlatforms.includes(p.id);
                      return (
                        <button
                          key={p.id}
                          onClick={() => togglePlatform(p.id)}
                          className={clsx(
                             "flex flex-col items-center justify-center p-2 rounded-xl border-2 transition-all gap-1 h-20 group relative overflow-hidden",
                             isSelected 
                               ? `bg-slate-800 border-blue-500 shadow-[0_0_15px_rgba(59,130,246,0.3)] z-10 scale-[1.02]` 
                               : "bg-slate-900 border-slate-800 opacity-70 hover:opacity-100 hover:border-slate-600"
                          )}
                          title={p.label}
                        >
                           {isSelected && <div className="absolute inset-0 bg-blue-600/5 pointer-events-none"></div>}
                           {isSelected && <div className="absolute top-1 right-1"><CheckCircle className="w-3 h-3 text-blue-500" /></div>}
                           {Icon && <Icon className={clsx("w-6 h-6 transition-transform group-hover:scale-110", isSelected ? p.color : "text-slate-400")} />}
                           <span className={clsx("text-[10px] font-bold text-center leading-tight", isSelected ? "text-white" : "text-slate-500")}>
                               {p.label.split('(')[0]}
                           </span>
                        </button>
                      );
                   })}
                </div>
             </div>

             <div className="mb-6">
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Post Type</label>
                <div className="grid grid-cols-2 gap-2">
                   {FORMATS.map(f => {
                      const isSelected = selectedFormat === f.id;
                      return (
                        <button 
                            key={f.id}
                            onClick={() => setSelectedFormat(f.id)}
                            className={clsx(
                                "relative flex items-center p-2 rounded-xl border-2 transition-all gap-3 h-14 text-left group",
                                isSelected 
                                ? "bg-purple-900/20 border-purple-500 text-white shadow-lg shadow-purple-900/20" 
                                : "bg-slate-900 border-slate-800 text-slate-400 hover:border-slate-600 hover:bg-slate-800"
                            )}
                        >
                            <div className={clsx("shrink-0 flex items-center justify-center w-8 h-8 rounded transition-colors", isSelected ? "text-white" : "text-slate-500 group-hover:text-slate-300")}>
                                {renderFormatShape(f.id, isSelected)}
                            </div>
                            <span className={clsx("text-xs font-bold", isSelected ? "text-white" : "text-slate-300")}>{f.label}</span>
                        </button>
                      );
                   })}
                </div>
             </div>

             <button
                onClick={handleGenerate}
                disabled={isGenerating || !coreMessage}
                className="w-full bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 disabled:from-slate-800 disabled:to-slate-800 disabled:text-slate-500 text-white px-6 py-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all shadow-lg shadow-blue-900/20 text-lg hover:scale-[1.02] active:scale-95"
               >
                 {isGenerating ? <Loader2 className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5" />}
                 Generate Posts
             </button>
          </div>
        </div>

        {/* Results Panel */}
        <div className="lg:col-span-8 space-y-4 h-full overflow-y-auto pb-20 pr-2" ref={resultsRef}>
          {generatedPosts.length === 0 && !isGenerating && (
            <div className="h-full flex flex-col items-center justify-center text-slate-600 border-2 border-dashed border-slate-800 rounded-xl min-h-[400px]">
              <div className="p-4 bg-slate-900 rounded-full mb-4">
                 <Sparkles className="w-8 h-8 text-blue-900" />
              </div>
              <h3 className="text-lg font-bold text-slate-400 mb-2">Ready to create magic?</h3>
              <p className="text-sm max-w-xs text-center">Select your target platforms on the left and hit Generate.</p>
            </div>
          )}

          {isGenerating && (
            <div className="space-y-4">
              {[1, 2].map(i => (
                <div key={i} className="animate-pulse bg-slate-950 border border-slate-800 rounded-xl p-6 h-48"></div>
              ))}
            </div>
          )}

          {generatedPosts.length > 0 && (
             <div className="flex items-center justify-between bg-slate-900/50 border border-slate-800 rounded-lg p-3 sticky top-0 z-10 backdrop-blur-md">
                <div className="flex items-center gap-3">
                    <input 
                        type="checkbox"
                        checked={selectedIds.length > 0 && selectedIds.length === generatedPosts.length}
                        onChange={handleSelectAll}
                        className="w-5 h-5 rounded border-slate-700 bg-slate-950 text-blue-600 focus:ring-blue-500 cursor-pointer"
                    />
                    <span className="text-sm font-medium text-slate-400">
                        {selectedIds.length > 0 ? `${selectedIds.length} Selected` : 'Select All'}
                    </span>
                </div>
                {selectedIds.length > 0 && (
                    <button 
                        onClick={handleBulkSchedule}
                        className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-1.5 rounded-lg text-sm font-medium transition-colors flex items-center gap-2 shadow-lg shadow-blue-900/20"
                    >
                        <Calendar className="w-4 h-4" />
                        Schedule ({selectedIds.length})
                    </button>
                )}
             </div>
          )}

          {generatedPosts.map((post) => (
            <div key={post.id} className="bg-slate-950 border border-slate-800 rounded-xl p-6 group hover:border-slate-700 transition-all relative">
              <div className="absolute top-6 left-6">
                 <input 
                    type="checkbox"
                    checked={selectedIds.includes(post.id)}
                    onChange={() => handleToggleSelect(post.id)}
                    className="w-5 h-5 rounded border-slate-700 bg-slate-900 text-blue-600 focus:ring-blue-500 cursor-pointer"
                 />
              </div>

              <div className="flex justify-between items-start mb-4 pl-8">
                <div className="flex items-center gap-2">
                   <span className={clsx(
                     "px-2 py-1 rounded text-xs font-bold uppercase tracking-wider",
                     PLATFORMS.find(p => p.id === post.platform)?.color.replace('text-', 'bg-').replace('600', '900').replace('500', '900').replace('400', '900') + " bg-opacity-30 " + PLATFORMS.find(p => p.id === post.platform)?.color.replace('text-', 'text-')
                   )}>
                     {post.platform}
                   </span>
                   <span className="px-2 py-1 rounded text-xs font-bold uppercase tracking-wider bg-slate-800 text-slate-400">
                     {post.format || 'Post'}
                   </span>
                </div>

                <div className="flex items-center gap-2">
                    <button 
                       onClick={() => setRepurposeTargetId(post.id)}
                       className="text-xs text-blue-400 hover:text-white flex items-center gap-1 px-2 py-1 hover:bg-slate-900 rounded transition-colors"
                       title="Transform for another platform"
                    >
                       <RefreshCw className="w-3 h-3" /> Remix
                    </button>
                    <div className="h-4 w-px bg-slate-800"></div>
                    <span className={`text-sm font-bold ${post.voiceScore > 80 ? 'text-emerald-400' : 'text-amber-400'}`}>
                        {post.voiceScore}% Voice
                    </span>
                </div>
              </div>

              <div className="pl-8 grid grid-cols-1 md:grid-cols-2 gap-6">
                 <div>
                    <label className="text-[10px] text-slate-500 uppercase font-bold mb-1 block">Caption / Script</label>
                    <textarea 
                        className="w-full bg-transparent text-slate-300 text-base mb-2 leading-relaxed whitespace-pre-wrap font-light focus:outline-none resize-none focus:bg-slate-900/50 rounded p-2 -ml-2 transition-colors border border-transparent focus:border-slate-700"
