                            <div className="relative z-10">
                                <textarea 
                                    className="w-full bg-slate-800/50 text-xs text-slate-300 italic leading-relaxed resize-none focus:outline-none focus:bg-slate-800 focus:ring-1 focus:ring-purple-500/50 rounded-lg p-3 border border-slate-700/50 transition-all pr-12"
                                    value={post.visualPrompt || ''}
                                    onChange={(e) => handleUpdatePost(post.id, 'visualPrompt', e.target.value)}
                                    rows={3}
                                    placeholder="Describe the image you want..."
                                />
                                {post.visualPrompt && (
                                    <button
                                        onClick={() => handleGenerateImage(post)}
                                        disabled={generatingImageForId === post.id}
                                        className="absolute bottom-2 right-2 p-1.5 bg-purple-600 hover:bg-purple-500 text-white rounded-md shadow-lg transition-colors disabled:opacity-50"
                                        title="Generate Image"
                                    >
                                        {generatingImageForId === post.id ? <Loader2 className="w-3 h-3 animate-spin" /> : <Wand2 className="w-3 h-3" />}
                                    </button>
                                )}
                            </div>
                        </div>
                    )}

                    {post.flaggedKeywords.length > 0 && (
                        <div className="p-3 bg-amber-900/10 border border-amber-900/30 rounded-lg flex items-start gap-2">
                            <AlertTriangle className="w-4 h-4 text-amber-500 shrink-0 mt-0.5" />
                            <div>
                                <p className="text-xs font-bold text-amber-400">Quality Check</p>
                                <p className="text-[10px] text-amber-300/80">
                                Contains: {post.flaggedKeywords.join(', ')}
                                </p>
                            </div>
                        </div>
                    )}
                 </div>
              </div>

              <div className="flex flex-wrap justify-end gap-3 pt-4 border-t border-slate-900 pl-8 mt-4">
                <button onClick={() => navigator.clipboard.writeText(post.content)} className="p-2 text-slate-500 hover:text-white transition-colors" title="Copy text"><Copy className="w-5 h-5" /></button>
                <button onClick={() => handleSaveDraft(post)} className="bg-slate-900 border border-slate-800 hover:bg-slate-800 text-slate-300 px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"><Save className="w-4 h-4" /> Save Draft</button>
                <button onClick={() => handleSingleAction(post)} className="bg-slate-800 hover:bg-slate-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"><Calendar className="w-4 h-4 text-blue-500" /> Schedule</button>
              </div>
