                        <div className="bg-gradient-to-br from-slate-900 to-slate-900 border border-slate-800 rounded-xl p-4 relative overflow-hidden group/visual">
                            {/* Decorative glow */}
                            <div className="absolute top-0 right-0 w-24 h-24 bg-purple-900/20 blur-2xl rounded-full -mr-10 -mt-10"></div>

                            <div className="flex items-center gap-2 mb-3 relative z-10">
                                <ImageIcon className="w-4 h-4 text-purple-400" />
                                <span className="text-xs font-bold text-purple-300">AI Visual Idea</span>
                            </div>

                            <div className="relative z-10">
                                <textarea 
                                    className="w-full bg-slate-800/50 text-xs text-slate-300 italic leading-relaxed resize-none focus:outline-none focus:bg-slate-800 focus:ring-1 focus:ring-purple-500/50 rounded-lg p-3 border border-slate-700/50 transition-all pr-12"
                                    value={post.visualPrompt || ''}
                                    onChange={(e) => handleUpdatePost(post.id, 'visualPrompt', e.target.value)}
                                    rows={3}
                                    placeholder="Describe the image you want..."
                                />
                                {post.visualPrompt && (
                                    <button
                                        onClick={() => handleGenerateImage(post)}
                                        disabled={generatingImageForId === post.id}
                                        className="absolute bottom-2 right-2 p-1.5 bg-purple-600 hover:bg-purple-500 text-white rounded-md shadow-lg transition-colors disabled:opacity-50"
                                        title="Generate Image"
                                    >
                                        {generatingImageForId === post.id ? <Loader2 className="w-3 h-3 animate-spin" /> : <Wand2 className="w-3 h-3" />}
                                    </button>
                                )}
                            </div>
                        </div>
                    )}

                    {post.flaggedKeywords.length > 0 && (
                        <div className="p-3 bg-amber-900/10 border border-amber-900/30 rounded-lg flex items-start gap-2">
                            <AlertTriangle className="w-4 h-4 text-amber-500 shrink-0 mt-0.5" />
                            <div>
                                <p className="text-xs font-bold text-amber-400">Quality Check</p>
                                <p className="text-[10px] text-amber-300/80">
                                Contains: {post.flaggedKeywords.join(', ')}
                                </p>
                            </div>
                        </div>
                    )}
                 </div>
              </div>

              <div className="flex flex-wrap justify-end gap-3 pt-4 border-t border-slate-900 pl-8 mt-4">
                <button onClick={() => navigator.clipboard.writeText(post.content)} className="p-2 text-slate-500 hover:text-white transition-colors" title="Copy text"><Copy className="w-5 h-5" /></button>
                <button onClick={() => handleSaveDraft(post)} className="bg-slate-900 border border-slate-800 hover:bg-slate-800 text-slate-300 px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"><Save className="w-4 h-4" /> Save Draft</button>
                <button onClick={() => handleSingleAction(post)} className="bg-slate-800 hover:bg-slate-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"><Calendar className="w-4 h-4 text-blue-500" /> Schedule</button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default ContentStudio;

import React, { useState, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import { SocialPost, PostStatus, ContentFormat, Platform } from '../types';
import { Sparkles, AlertTriangle, CheckCircle, Copy, Loader2, Calendar, X, Instagram, Facebook, Linkedin, Twitter, Youtube, RefreshCw, Image as ImageIcon, Save, Wand2, Pin, MapPin, Ghost, Hash, Video, AtSign, FileText, Smartphone, Film, MonitorPlay, GalleryHorizontal, ListTree, Layers, Lightbulb, Play, Star } from 'lucide-react';
import clsx from 'clsx';

const PLATFORMS: { id: Platform; label: string; icon: any; color: string }[] = [
  { id: 'Facebook', label: 'Facebook', icon: Facebook, color: 'text-blue-600' },
  { id: 'Instagram', label: 'Instagram', icon: Instagram, color: 'text-pink-500' },
  { id: 'LinkedIn', label: 'LinkedIn', icon: Linkedin, color: 'text-blue-700' },
  { id: 'Twitter', label: 'Twitter (X)', icon: Twitter, color: 'text-sky-500' },
  { id: 'TikTok', label: 'TikTok', icon: Video, color: 'text-teal-400' },
  { id: 'YouTube', label: 'YouTube', icon: Youtube, color: 'text-red-600' },
  { id: 'Pinterest', label: 'Pinterest', icon: Pin, color: 'text-red-500' },
  { id: 'Google Business', label: 'Google Business', icon: MapPin, color: 'text-blue-500' },
  { id: 'Snapchat', label: 'Snapchat', icon: Ghost, color: 'text-yellow-400' },
  { id: 'Reddit', label: 'Reddit', icon: Hash, color: 'text-orange-500' },
  { id: 'Threads', label: 'Threads', icon: AtSign, color: 'text-slate-200' },
];

const FORMATS: { id: ContentFormat; label: string; icon: any }[] = [
  { id: 'Post', label: 'Post', icon: FileText },
  { id: 'Story', label: 'Story', icon: Smartphone },
  { id: 'Reel', label: 'Reel', icon: Film },
  { id: 'Video', label: 'Video Script', icon: MonitorPlay },
  { id: 'Carousel', label: 'Carousel', icon: GalleryHorizontal },
  { id: 'Thread', label: 'Thread', icon: ListTree },
];

const CATEGORIZED_IDEAS = {
    "Sell 💰": ["🎉 New Product Launch", "📅 Upcoming Sale", "⚡ Flash Deal"],
    "Engage 💬": ["👋 Introduce the Team", "❓ Ask a Question", "🗳️ Poll"],
    "Share 🤝": ["💡 Tip of the Day", "❤️ Customer Review", "🔒 Behind Scenes"]
};

const ContentStudio: React.FC = () => {
  const { generateContent, repurposePost, generateImage, addPost, restrictedTerms, integrations } = useApp();
  const location = useLocation();
  const resultsRef = useRef<HTMLDivElement>(null);

  const [coreMessage, setCoreMessage] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedPosts, setGeneratedPosts] = useState<SocialPost[]>([]);

  // Generation Settings
  const [selectedPlatforms, setSelectedPlatforms] = useState<Platform[]>(['Instagram', 'LinkedIn', 'Twitter']);
  const [selectedFormat, setSelectedFormat] = useState<ContentFormat>('Post');

  // Selection & Scheduling State
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [postsToSchedule, setPostsToSchedule] = useState<SocialPost[]>([]);
  const [scheduleDate, setScheduleDate] = useState('');

  // Repurpose State
  const [repurposeTargetId, setRepurposeTargetId] = useState<string | null>(null);
  const [repurposePlatform, setRepurposePlatform] = useState<Platform>('Instagram');
  const [repurposeFormat, setRepurposeFormat] = useState<ContentFormat>('Story');
  const [isRepurposing, setIsRepurposing] = useState(false);

  // Image Gen State
  const [generatingImageForId, setGeneratingImageForId] = useState<string | null>(null);

  // Handle incoming data
  useEffect(() => {
    if (location.state) {
      const { coreMessage, platforms, format } = location.state as any;
      if (coreMessage) setCoreMessage(coreMessage);
      if (platforms) setSelectedPlatforms(platforms);
      if (format) setSelectedFormat(format);
      window.history.replaceState({}, document.title);
    }
  }, [location.state]);

  const togglePlatform = (p: Platform) => {
    setSelectedPlatforms(prev => 
      prev.includes(p) ? prev.filter(x => x !== p) : [...prev, p]
    );
  };

  const handleSelectAllPlatforms = () => {
    if (selectedPlatforms.length === PLATFORMS.length) {
        setSelectedPlatforms([]);
    } else {
        setSelectedPlatforms(PLATFORMS.map(p => p.id));
    }
  };

  const handleUpdatePost = (id: string, field: keyof SocialPost, value: any) => {
    setGeneratedPosts(prev => prev.map(p => 
      p.id === id ? { ...p, [field]: value } : p
    ));
  };

  const handleGenerate = async () => {
    if (!coreMessage.trim()) return;
    if (selectedPlatforms.length === 0) {
      alert("Please select at least one platform (e.g. Facebook).");
      return;
    }
    setIsGenerating(true);
    setSelectedIds([]);
    try {
      const posts = await generateContent(coreMessage, { platforms: selectedPlatforms, format: selectedFormat });
      setGeneratedPosts(posts);

      // Auto-scroll to results on mobile/desktop
      setTimeout(() => {
          resultsRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }, 500);

    } catch (e) {
      console.error(e);
      alert("Failed to generate. Please check your connection.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleGenerateImage = async (post: SocialPost) => {
    if (!post.visualPrompt) return;
    setGeneratingImageForId(post.id);
    try {
        const imageUrl = await generateImage(post.visualPrompt);
        if (imageUrl) {
            setGeneratedPosts(prev => prev.map(p => 
                p.id === post.id ? { ...p, imageUrl } : p
            ));
        } else {
            alert("Failed to generate image. Try again.");
        }
    } catch (e) {
        console.error(e);
        alert("Error generating image.");
    } finally {
        setGeneratingImageForId(null);
    }
  };

  const handleRepurpose = async (originalPost: SocialPost) => {
    setIsRepurposing(true);
    try {
       const newPost = await repurposePost(originalPost, repurposePlatform, repurposeFormat);
       setGeneratedPosts(prev => [newPost, ...prev]);
       setRepurposeTargetId(null); 
    } catch (e) {
       alert("Failed to repurpose.");
    } finally {
       setIsRepurposing(false);
    }
  };

  const handleToggleSelect = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(pid => pid !== id) : [...prev, id]);
  };

  const handleSelectAll = () => {
    if (selectedIds.length === generatedPosts.length) {
      setSelectedIds([]);
    } else {
      setSelectedIds(generatedPosts.map(p => p.id));
    }
  };

  const openScheduleModal = (posts: SocialPost[]) => {
      setPostsToSchedule(posts);
      const tomorrow = new Date();
      tomorrow.setDate(tomorrow.getDate() + 1);
      tomorrow.setHours(9, 0, 0, 0);
      const pad = (n: number) => n.toString().padStart(2, '0');
      const year = tomorrow.getFullYear();
      const month = pad(tomorrow.getMonth() + 1);
      const day = pad(tomorrow.getDate());
      const hour = pad(tomorrow.getHours());
      const minute = pad(tomorrow.getMinutes());
      setScheduleDate(`${year}-${month}-${day}T${hour}:${minute}`);
  };

  const handleSingleAction = (post: SocialPost) => {
    if (post.flaggedKeywords.length > 0) {
      addPost(post);
      setGeneratedPosts(prev => prev.filter(p => p.id !== post.id));
      setSelectedIds(prev => prev.filter(id => id !== post.id));
      alert("Saved to Approvals. This post has some quality flags.");
    } else {
      openScheduleModal([post]);
    }
  };

  const handleSaveDraft = (post: SocialPost) => {
    addPost({ ...post, status: PostStatus.DRAFT });
    setGeneratedPosts(prev => prev.filter(p => p.id !== post.id));
    setSelectedIds(prev => prev.filter(id => id !== post.id));
  };

  const handleBulkSchedule = () => {
    const selected = generatedPosts.filter(p => selectedIds.includes(p.id));
    if (selected.length === 0) return;
    openScheduleModal(selected);
  };

  const handleConfirmSchedule = () => {
    if (postsToSchedule.length === 0) return;
    if (!scheduleDate) {
      alert("Please select a date and time.");
      return;
    }
    const timestamp = new Date(scheduleDate).getTime();
    postsToSchedule.forEach(post => {
        const isFlagged = restrictedTerms.some(term => post.content.toLowerCase().includes(term.toLowerCase()));
        addPost({
            ...post,
            status: PostStatus.SCHEDULED,
            scheduledTime: timestamp
        });
    });

    const scheduledIds = postsToSchedule.map(p => p.id);
    setGeneratedPosts(prev => prev.filter(p => !scheduledIds.includes(p.id)));
    setSelectedIds(prev => prev.filter(id => !scheduledIds.includes(id)));
    setPostsToSchedule([]);
    setScheduleDate('');
  };

  // Improved Render Visual Shape for Content Format
  const renderFormatVisual = (id: ContentFormat, isSelected: boolean) => {
    const strokeClass = isSelected ? "stroke-purple-400" : "stroke-slate-600";
    const fillClass = isSelected ? "fill-purple-400" : "fill-slate-600";
    const bgClass = isSelected ? "bg-purple-500/20" : "bg-slate-800";
    const borderClass = isSelected ? "border-purple-500" : "border-slate-600";
    const textClass = isSelected ? "bg-purple-400" : "bg-slate-600";

    switch(id) {
        case 'Post':
            return (
                <div className={clsx("w-10 h-10 border-2 rounded-md flex flex-col p-1 gap-1", borderClass, bgClass)}>
                    <div className={clsx("w-full h-5 rounded-sm opacity-50", textClass)}></div>
                    <div className={clsx("w-full h-0.5 rounded-full", textClass)}></div>
                    <div className={clsx("w-2/3 h-0.5 rounded-full", textClass)}></div>
                </div>
            );
        case 'Story':
            return (
                <div className={clsx("w-8 h-12 border-2 rounded-lg flex flex-col items-center p-1 gap-1", borderClass, bgClass)}>
                     <div className={clsx("w-2 h-0.5 rounded-full mb-0.5", textClass)}></div>
                     <div className={clsx("w-full h-full rounded-sm opacity-30", textClass)}></div>
                </div>
            );
        case 'Reel':
            return (
                <div className={clsx("w-8 h-12 border-2 rounded-lg flex items-center justify-center relative", borderClass, bgClass)}>
                    <Play className={clsx("w-4 h-4 ml-0.5", fillClass)} />
                    <div className={clsx("absolute bottom-1 w-4 h-0.5 rounded-full opacity-50", textClass)}></div>
                </div>
            );
         case 'Video':
            return (
                <div className={clsx("w-14 h-9 border-2 rounded-md flex items-center justify-center", borderClass, bgClass)}>
                    <Play className={clsx("w-5 h-5 ml-0.5", fillClass)} />
                </div>
            );
         case 'Carousel':
            return (
                <div className="relative w-10 h-10 flex items-center justify-center">
                    <div className={clsx("absolute w-8 h-10 border-2 rounded-md transform -rotate-6 -translate-x-1", isSelected ? "border-purple-500/40 bg-purple-500/10" : "border-slate-700 bg-slate-800")}></div>
                    <div className={clsx("absolute w-8 h-10 border-2 rounded-md transform rotate-6 translate-x-1 z-10", borderClass, bgClass)}></div>
                </div>
            );
         case 'Thread':
             return (
                 <div className="flex flex-col items-center gap-1">
                     <div className={clsx("w-10 h-4 border-2 rounded-full", borderClass, bgClass)}></div>
                     <div className={clsx("w-0.5 h-1.5", textClass)}></div>
                     <div className={clsx("w-10 h-4 border-2 rounded-full opacity-70", borderClass, bgClass)}></div>
                 </div>
             );
    }
  }

  const getRecommendedFormats = (platform: Platform): ContentFormat[] => {
      switch(platform) {
          case 'Instagram': return ['Reel', 'Story', 'Carousel'];
          case 'TikTok': return ['Reel'];
          case 'YouTube': return ['Video', 'Reel'];
          case 'LinkedIn': return ['Post', 'Carousel'];
          case 'Twitter': return ['Post', 'Thread'];
          case 'Pinterest': return ['Post'];
          case 'Facebook': return ['Post', 'Reel', 'Story'];
          case 'Threads': return ['Thread', 'Post'];
          default: return ['Post'];
      }
  };

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col space-y-6 relative">

      {/* Scheduling Modal */}
      {postsToSchedule.length > 0 && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4">
           <div className="bg-slate-950 border border-slate-700 rounded-xl p-6 w-full max-w-md shadow-2xl max-h-[90vh] overflow-y-auto">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold text-white flex items-center gap-2">
                  <Calendar className="w-5 h-5 text-blue-500" />
                  Schedule {postsToSchedule.length} Post{postsToSchedule.length > 1 ? 's' : ''}
                </h3>
                <button onClick={() => setPostsToSchedule([])} className="text-slate-400 hover:text-white"><X className="w-5 h-5" /></button>
              </div>
              <div className="mb-6">
                <input type="datetime-local" className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-600 focus:outline-none" value={scheduleDate} onChange={(e) => setScheduleDate(e.target.value)} />
              </div>
              <div className="flex justify-end gap-3">
                <button onClick={() => setPostsToSchedule([])} className="px-4 py-2 text-slate-400 hover:text-white">Cancel</button>
                <button onClick={handleConfirmSchedule} className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-bold">Confirm</button>
              </div>
           </div>
        </div>
      )}

      {/* Repurpose Modal */}
      {repurposeTargetId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4">
           <div className="bg-slate-950 border border-slate-700 rounded-xl p-6 w-full max-w-3xl shadow-2xl max-h-[90vh] overflow-y-auto">
              <div className="flex justify-between items-center mb-6">
                 <h3 className="text-xl font-bold text-white">Repurpose Content</h3>
                 <button onClick={() => setRepurposeTargetId(null)} className="text-slate-400"><X className="w-5 h-5" /></button>
              </div>

              <div className="grid md:grid-cols-2 gap-8 mb-6">
                 <div>
                    <h4 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-2">Original Post</h4>
                    <div className="bg-slate-900 p-4 rounded-lg border border-slate-800 text-slate-300 text-sm italic">
                        "{generatedPosts.find(p => p.id === repurposeTargetId)?.content}"
                    </div>
                 </div>

                 <div>
                    <h4 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-2">Target Platform</h4>
                    <div className="space-y-4">
                        <div className="grid grid-cols-3 gap-2">
                            {PLATFORMS.slice(0, 9).map(p => {
                                const originalPost = generatedPosts.find(post => post.id === repurposeTargetId);
                                const isRec = originalPost && (() => {
                                    const map: Record<string, string[]> = {
                                        'Twitter': ['LinkedIn', 'Instagram', 'Threads'],
                                        'LinkedIn': ['Twitter', 'Facebook', 'Instagram'],
                                        'Instagram': ['TikTok', 'Facebook', 'Pinterest'],
                                        'TikTok': ['Instagram', 'YouTube'],
                                        'Facebook': ['Instagram', 'LinkedIn'],
                                        'YouTube': ['TikTok', 'Instagram'],
                                    };
                                    return map[originalPost.platform]?.includes(p.id);
                                })();
                                const Icon = p.icon;

                                return (
                                    <button
                                        key={p.id}
                                        onClick={() => {
                                            setRepurposePlatform(p.id);
                                            const rec = getRecommendedFormats(p.id);
                                            setRepurposeFormat(rec[0]);
                                        }}
                                        className={clsx(
                                            "flex flex-col items-center justify-center p-3 rounded-lg border text-xs font-bold transition-all relative overflow-visible gap-1.5",
                                            repurposePlatform === p.id 
                                            ? "bg-blue-600 border-blue-500 text-white" 
                                            : "bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-600"
                                        )}
                                    >
                                        {isRec && (
                                            <span className="absolute -top-2 -right-2 z-20 bg-emerald-500 text-slate-900 text-[9px] px-1.5 py-0.5 rounded-full font-bold shadow-sm flex items-center gap-0.5 border border-emerald-400">
                                                <Star className="w-2 h-2 fill-current" /> Best
                                            </span>
                                        )}
                                        {Icon && <Icon className={clsx("w-5 h-5", repurposePlatform === p.id ? "text-white" : p.color)} />}
                                        {p.id}
                                    </button>
                                );
                            })}
                        </div>

                        <div>
                            <h4 className="text-xs font-bold text-slate-500 mb-2">Format</h4>
                            <div className="flex gap-2">
                                {getRecommendedFormats(repurposePlatform).map((fmt, idx) => {
                                    const originalPost = generatedPosts.find(post => post.id === repurposeTargetId);
                                    const isRec = originalPost && (() => {
                                        const sFmt = originalPost.format || 'Post';
                                        // Video -> Video
                                        if (['Reel', 'Video'].includes(sFmt) && ['Reel', 'Video'].includes(fmt)) return true;
                                        // Text -> Text/Image adaptation
                                        if (sFmt === 'Post' && (fmt === 'Post' || fmt === 'Story')) return true;
                                        if (sFmt === 'Thread' && (fmt === 'Carousel' || fmt === 'Post')) return true;
                                        if (sFmt === 'Carousel' && fmt === 'Carousel') return true;
                                        // Fallback default
                                        return idx === 0;
                                    })();

                                    return (
                                        <button
                                            key={fmt}
                                            onClick={() => setRepurposeFormat(fmt)}
                                            className={clsx(
                                                "px-3 py-1.5 rounded-full text-xs font-bold border transition-all flex items-center",
                                                repurposeFormat === fmt
                                                ? "bg-purple-600 border-purple-500 text-white"
                                                : "bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-600"
                                            )}
                                        >
                                            {fmt}
                                            {isRec && <span className="ml-1.5 bg-emerald-500/20 text-emerald-400 text-[9px] px-1.5 py-0.5 rounded-full uppercase tracking-wider">Rec</span>}
                                        </button>
                                    );
                                })}
                            </div>
                        </div>
                    </div>
                 </div>
              </div>

              <div className="flex justify-end gap-3 pt-6 border-t border-slate-800">
                 <button onClick={() => setRepurposeTargetId(null)} className="px-5 py-2.5 text-slate-400 hover:text-white transition-colors">Cancel</button>
                 <button onClick={() => handleRepurpose(generatedPosts.find(p => p.id === repurposeTargetId)!)} disabled={isRepurposing} className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-2.5 rounded-lg font-bold transition-all flex items-center gap-2">
                    {isRepurposing ? <Loader2 className="w-4 h-4 animate-spin" /> : <RefreshCw className="w-4 h-4" />}
                    Generate Remix
                 </button>
              </div>
           </div>
        </div>
      )}

      <div className="flex justify-between items-center shrink-0">
        <div>
           <h2 className="text-2xl md:text-3xl font-bold text-white">Create Post</h2>
           <p className="text-slate-400 text-sm md:text-base">Turn a simple idea into posts for all your channels.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 h-full min-h-0">
        {/* Left Config Panel */}
        <div className="lg:col-span-4 h-full overflow-y-auto pr-2 pb-10">
          <div className="bg-slate-950 border border-slate-800 rounded-xl p-5">
             <div className="mb-6">
                <label className="block text-sm font-bold text-slate-200 mb-3 flex items-center gap-2">
                    <Lightbulb className="w-4 h-4 text-yellow-400" /> What do you want to post about?
                </label>

                {/* Categorized Idea Starters */}
                <div className="space-y-2 mb-4">
                    {Object.entries(CATEGORIZED_IDEAS).map(([category, ideas]) => (
                        <div key={category} className="flex flex-wrap gap-2">
                            <span className="text-[10px] font-bold text-slate-500 uppercase tracking-wider w-full">{category}</span>
                            {ideas.map(idea => (
                                <button 
                                    key={idea} 
                                    onClick={() => setCoreMessage(prev => prev ? prev + " " + idea : idea)}
                                    className="text-[10px] bg-slate-900 hover:bg-slate-800 border border-slate-800 hover:border-slate-600 text-slate-300 px-3 py-1.5 rounded-lg transition-colors shadow-sm"
                                >
                                    {idea}
                                </button>
                            ))}
                        </div>
                    ))}
                </div>

                <textarea
                  className="w-full h-32 bg-slate-900 border border-slate-800 rounded-xl p-4 text-white focus:ring-2 focus:ring-blue-600 focus:outline-none resize-none placeholder-slate-600 text-sm leading-relaxed"
                  placeholder="e.g. We have a special on croissants this weekend! Buy one get one free. #weekendvibes"
                  value={coreMessage}
                  onChange={(e) => setCoreMessage(e.target.value)}
                />
             </div>

             <div className="mb-6">
                <div className="flex justify-between items-center mb-3">
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider">Target Platforms</label>
