                    <input 
                        type="checkbox"
                        checked={selectedIds.length > 0 && selectedIds.length === generatedPosts.length}
                        onChange={handleSelectAll}
                        className="w-5 h-5 rounded border-slate-700 bg-slate-950 text-blue-600 focus:ring-blue-500 cursor-pointer"
                    />
                    <span className="text-sm font-medium text-slate-400">
                        {selectedIds.length > 0 ? `${selectedIds.length} Selected` : 'Select All'}
                    </span>
                </div>
                {selectedIds.length > 0 && (
                    <button 
                        onClick={handleBulkSchedule}
                        className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-1.5 rounded-lg text-sm font-medium transition-colors flex items-center gap-2 shadow-lg shadow-blue-900/20"
                    >
                        <Calendar className="w-4 h-4" />
                        Schedule ({selectedIds.length})
                    </button>
                )}
             </div>
          )}

          {generatedPosts.map((post) => (
            <div key={post.id} className="bg-slate-950 border border-slate-800 rounded-xl p-6 group hover:border-slate-700 transition-all relative">
              <div className="absolute top-6 left-6">
                 <input 
                    type="checkbox"
                    checked={selectedIds.includes(post.id)}
                    onChange={() => handleToggleSelect(post.id)}
                    className="w-5 h-5 rounded border-slate-700 bg-slate-900 text-blue-600 focus:ring-blue-500 cursor-pointer"
                 />
              </div>

              <div className="flex justify-between items-start mb-4 pl-8">
                <div className="flex items-center gap-2">
                   <span className={clsx(
                     "px-2 py-1 rounded text-xs font-bold uppercase tracking-wider",
                     PLATFORMS.find(p => p.id === post.platform)?.color.replace('text-', 'bg-').replace('600', '900').replace('500', '900').replace('400', '900') + " bg-opacity-30 " + PLATFORMS.find(p => p.id === post.platform)?.color.replace('text-', 'text-')
                   )}>
                     {post.platform}
                   </span>
                   <span className="px-2 py-1 rounded text-xs font-bold uppercase tracking-wider bg-slate-800 text-slate-400">
                     {post.format || 'Post'}
                   </span>
                </div>

                <div className="flex items-center gap-2">
                    <button 
                       onClick={() => setRepurposeTargetId(post.id)}
                       className="text-xs text-blue-400 hover:text-white flex items-center gap-1 px-2 py-1 hover:bg-slate-900 rounded transition-colors"
                       title="Transform for another platform"
                    >
                       <RefreshCw className="w-3 h-3" /> Remix
                    </button>
                    <div className="h-4 w-px bg-slate-800"></div>
                    <span className={`text-sm font-bold ${post.voiceScore > 80 ? 'text-emerald-400' : 'text-amber-400'}`}>
                        {post.voiceScore}% Voice
                    </span>
                </div>
              </div>

              <div className="pl-8 grid grid-cols-1 md:grid-cols-2 gap-6">
                 <div>
                    <label className="text-[10px] text-slate-500 uppercase font-bold mb-1 block">Caption / Script</label>
                    <textarea 
                        className="w-full bg-transparent text-slate-300 text-base mb-2 leading-relaxed whitespace-pre-wrap font-light focus:outline-none resize-none focus:bg-slate-900/50 rounded p-2 -ml-2 transition-colors border border-transparent focus:border-slate-700"
                        rows={6}
                        value={post.content}
                        onChange={(e) => handleUpdatePost(post.id, 'content', e.target.value)}
                    />
                 </div>

                 <div className="space-y-4">
                    {post.imageUrl ? (
                        <div className="space-y-2 animate-fade-in">
                            <label className="text-[10px] text-slate-500 uppercase font-bold block">Generated Image</label>
                            <img src={post.imageUrl} alt="AI Generated" className="w-full h-auto rounded-lg border border-slate-700 bg-slate-900" />
                            <div className="flex justify-between items-center gap-2 bg-slate-900/50 p-2 rounded border border-slate-800">
                                <div className="flex-1">
                                    <input 
                                        className="w-full bg-transparent text-xs text-slate-400 italic focus:outline-none focus:text-white"
                                        value={post.visualPrompt || ''}
                                        onChange={(e) => handleUpdatePost(post.id, 'visualPrompt', e.target.value)}
                                        placeholder="Edit image prompt..."
                                    />
                                </div>
                                <button 
                                    onClick={() => handleGenerateImage(post)}
                                    disabled={generatingImageForId === post.id}
                                    className="text-xs text-blue-400 hover:text-white flex items-center gap-1 px-2 py-1 rounded hover:bg-slate-800 transition-colors"
                                >
                                    {generatingImageForId === post.id ? <Loader2 className="w-3 h-3 animate-spin" /> : <RefreshCw className="w-3 h-3" />}
                                    Regenerate
                                </button>
                            </div>
                        </div>
                    ) : (
                        <div className="bg-gradient-to-br from-slate-900 to-slate-900 border border-slate-800 rounded-xl p-4 relative overflow-hidden group/visual">
                            {/* Decorative glow */}
                            <div className="absolute top-0 right-0 w-24 h-24 bg-purple-900/20 blur-2xl rounded-full -mr-10 -mt-10"></div>

                            <div className="flex items-center gap-2 mb-3 relative z-10">
                                <ImageIcon className="w-4 h-4 text-purple-400" />
                                <span className="text-xs font-bold text-purple-300">AI Visual Idea</span>
                            </div>

                            <div className="relative z-10">
                                <textarea 
                                    className="w-full bg-slate-800/50 text-xs text-slate-300 italic leading-relaxed resize-none focus:outline-none focus:bg-slate-800 focus:ring-1 focus:ring-purple-500/50 rounded-lg p-3 border border-slate-700/50 transition-all pr-12"
                                    value={post.visualPrompt || ''}
                                    onChange={(e) => handleUpdatePost(post.id, 'visualPrompt', e.target.value)}
                                    rows={3}
                                    placeholder="Describe the image you want..."
                                />
                                {post.visualPrompt && (
                                    <button
                                        onClick={() => handleGenerateImage(post)}
                                        disabled={generatingImageForId === post.id}
                                        className="absolute bottom-2 right-2 p-1.5 bg-purple-600 hover:bg-purple-500 text-white rounded-md shadow-lg transition-colors disabled:opacity-50"
                                        title="Generate Image"
                                    >
                                        {generatingImageForId === post.id ? <Loader2 className="w-3 h-3 animate-spin" /> : <Wand2 className="w-3 h-3" />}
                                    </button>
                                )}
                            </div>
                        </div>
                    )}

                    {post.flaggedKeywords.length > 0 && (
                        <div className="p-3 bg-amber-900/10 border border-amber-900/30 rounded-lg flex items-start gap-2">
                            <AlertTriangle className="w-4 h-4 text-amber-500 shrink-0 mt-0.5" />
                            <div>
                                <p className="text-xs font-bold text-amber-400">Quality Check</p>
                                <p className="text-[10px] text-amber-300/80">
                                Contains: {post.flaggedKeywords.join(', ')}
                                </p>
                            </div>
                        </div>
                    )}
                 </div>
              </div>

              <div className="flex flex-wrap justify-end gap-3 pt-4 border-t border-slate-900 pl-8 mt-4">
                <button onClick={() => navigator.clipboard.writeText(post.content)} className="p-2 text-slate-500 hover:text-white transition-colors" title="Copy text"><Copy className="w-5 h-5" /></button>
                <button onClick={() => handleSaveDraft(post)} className="bg-slate-900 border border-slate-800 hover:bg-slate-800 text-slate-300 px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"><Save className="w-4 h-4" /> Save Draft</button>
                <button onClick={() => handleSingleAction(post)} className="bg-slate-800 hover:bg-slate-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"><Calendar className="w-4 h-4 text-blue-500" /> Schedule</button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default ContentStudio;

export type Platform = 'Twitter' | 'LinkedIn' | 'Instagram' | 'TikTok' | 'Facebook' | 'YouTube' | 'Pinterest' | 'Google Business' | 'Snapchat' | 'Reddit' | 'Threads';

export type ContentFormat = 'Post' | 'Story' | 'Reel' | 'Thread' | 'Carousel' | 'Video';

export type UserRole = 'Owner' | 'Editor' | 'Viewer' | 'SuperAdmin';

export type PaymentProvider = 'Stripe' | 'PayPal';

export interface AffiliateStats {
  code: string;
  referrals: number;
  earnings: number;
  payoutStatus: 'Paid' | 'Pending';
}

export interface Badge {
  id: string;
  name: string;
  icon: string;
  description: string;
}

export interface GamificationStats {
  level: number;
  points: number;
  badges: string[]; // Badge IDs
}

export interface UserProfile {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  companyName: string;
  plan: 'Starter' | 'Growth' | 'Pro';
  status: 'Active' | 'Suspended';
  joinedDate: number;
  avatar?: string;
  affiliate?: AffiliateStats;
  gamification?: GamificationStats;
}

export interface Transaction {
    id: string;
    userId: string;
    userEmail: string;
    amount: number;
    status: 'Succeeded' | 'Failed' | 'Refunded';
    date: number;
    provider: 'Stripe' | 'PayPal';
    type: 'Subscription' | 'AffiliatePayout';
}

export enum RiskLevel {
  SAFE = 'Safe',
  WARNING = 'Check',
  CRITICAL = 'Action Needed',
}

export enum PostStatus {
  DRAFT = 'Draft',
  NEEDS_REVIEW = 'Needs Review', // Was PENDING_COMPLIANCE
  APPROVED = 'Approved',
  REJECTED = 'Needs Edit',
  PUBLISHED = 'Published',
  SCHEDULED = 'Scheduled',
}

export interface SocialPost {
  id: string;
  content: string;
  platform: Platform;
  format?: ContentFormat;
  visualPrompt?: string; // AI suggestion for image/video
  imageUrl?: string; // Generated image URL
  voiceScore: number;
  status: PostStatus;
  timestamp: number;
  flaggedKeywords: string[];
  predictedEngagement?: string;
  author: string;
  scheduledTime?: number;
  // Performance metrics for Monitor
  metrics?: {
    views: number;
    likes: number;
    shares: number;
    clicks: number;
  }
}

export interface CampaignPostTemplate {
  dayOffset: number; // Day 1, Day 3, etc.
  platform: Platform;
  format: ContentFormat;
  intent: string; // "Teaser", "Launch", "Social Proof"
}

export interface Campaign {
  id: string;
  name: string;
  goal: string;
  startDate: number;
  status: 'Draft' | 'Active' | 'Completed';
  posts: string[]; // IDs of SocialPosts
  aiSummary?: string;
}

export interface IncomingMessage {
  id: string;
  sender: string;
  content: string;
  platform: Platform;
  timestamp: number;
  sentiment: 'Positive' | 'Neutral' | 'Negative' | 'Sarcastic';
  riskLevel: 'Low' | 'High';
  suggestedReply?: string;
  status: 'New' | 'Replied' | 'Escalated';
}

export interface BrandMention {
  id: string;
  user: string;
  content: string;
  platform: Platform;
  timestamp: number;
  sentiment: 'Positive' | 'Neutral' | 'Negative';
  keywordMatch: string;
}

export interface Competitor {
  id: string;
  name: string;
  handle: string;
  avatarColor: string;
  latestPost: {
    content: string;
    timestamp: number;
    likes: number;
  };
}

export interface BrandVoiceSettings {
  name: string;
  description: string;
  targetScore: number;
  tone: number; // 0 (Serious) to 100 (Playful)
}

export interface Integration {
  id: string;
  name: string;
  connected: boolean;
  icon: string;
  status?: 'active' | 'error' | 'testing';
  lastChecked?: number;
  latencyMs?: number;
}

export interface BillingPlan {
  name: 'Starter' | 'Growth' | 'Pro';
  price: number;
  interval: 'monthly' | 'yearly';
  features: string[];
  stripeId?: string;
  paypalId?: string;
}

export interface ContextTip {
  title: string;
  message: string;
  actionLabel?: string;
  actionLink?: string;
  type: 'info' | 'success' | 'warning';
}

