  { id: 'YouTube', label: 'YouTube', icon: Youtube, color: 'text-red-600', bg: 'bg-red-600' },
  { id: 'Pinterest', label: 'Pinterest', icon: Pin, color: 'text-red-500', bg: 'bg-red-500' },
