];

const FORMATS: { id: ContentFormat; label: string; icon: any }[] = [
  { id: 'Post', label: 'Post', icon: FileText },
  { id: 'Story', label: 'Story', icon: Smartphone },
  { id: 'Reel', label: 'Reel', icon: Film },
  { id: 'Video', label: 'Video Script', icon: MonitorPlay },
  { id: 'Carousel', label: 'Carousel', icon: GalleryHorizontal },
  { id: 'Thread', label: 'Thread', icon: ListTree },
];

const CATEGORIZED_IDEAS = {
    "Sell 💰": ["🎉 New Product Launch", "📅 Upcoming Sale", "⚡ Flash Deal"],
    "Engage 💬": ["👋 Introduce the Team", "❓ Ask a Question", "🗳️ Poll"],
    "Share 🤝": ["💡 Tip of the Day", "❤️ Customer Review", "🔒 Behind Scenes"]
};

const ContentStudio: React.FC = () => {
  const { generateContent, repurposePost, generateImage, addPost, restrictedTerms, currentUser } = useApp();
  const location = useLocation();
  const resultsRef = useRef<HTMLDivElement>(null);

  const [coreMessage, setCoreMessage] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedPosts, setGeneratedPosts] = useState<SocialPost[]>([]);

  // Generation Settings
  const [selectedPlatforms, setSelectedPlatforms] = useState<Platform[]>(['Instagram', 'LinkedIn', 'Twitter', 'Facebook']);
  const [selectedFormat, setSelectedFormat] = useState<ContentFormat>('Post');

  // Selection & Scheduling State
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [postsToSchedule, setPostsToSchedule] = useState<SocialPost[]>([]);
  const [scheduleDate, setScheduleDate] = useState('');

  // Repurpose State
  const [repurposeTargetId, setRepurposeTargetId] = useState<string | null>(null);
  const [repurposePlatform, setRepurposePlatform] = useState<Platform>('Instagram');
  const [repurposeFormat, setRepurposeFormat] = useState<ContentFormat>('Story');
  const [isRepurposing, setIsRepurposing] = useState(false);

  // Image Gen State
  const [generatingImageForId, setGeneratingImageForId] = useState<string | null>(null);

  // Handle incoming data
  useEffect(() => {
    if (location.state) {
      const { coreMessage, platforms, format } = location.state as any;
      if (coreMessage) setCoreMessage(coreMessage);
      if (platforms) setSelectedPlatforms(platforms);
      if (format) setSelectedFormat(format);
      window.history.replaceState({}, document.title);
    }
  }, [location.state]);

  const togglePlatform = (p: Platform) => {
    setSelectedPlatforms(prev => 
      prev.includes(p) ? prev.filter(x => x !== p) : [...prev, p]
    );
  };

  const handleSelectAllPlatforms = () => {
    if (selectedPlatforms.length === PLATFORMS.length) {
        setSelectedPlatforms([]);
    } else {
        setSelectedPlatforms(PLATFORMS.map(p => p.id));
    }
  };

  const handleUpdatePost = (id: string, field: keyof SocialPost, value: any) => {
    setGeneratedPosts(prev => prev.map(p => 
      p.id === id ? { ...p, [field]: value } : p
    ));
  };

  const handleEnhancePrompt = () => {
      if(!coreMessage) return;
      setCoreMessage(prev => prev + " (Make it engaging, professional, and viral-worthy)");
  };

  const handleGenerate = async () => {
    if (!coreMessage.trim()) return;
    if (selectedPlatforms.length === 0) {
      alert("Please select at least one platform (e.g. Facebook).");
      return;
    }
    setIsGenerating(true);
    setSelectedIds([]);
    try {
      const posts = await generateContent(coreMessage, { platforms: selectedPlatforms, format: selectedFormat });
      setGeneratedPosts(posts);

      // Auto-scroll to results on mobile/desktop
      setTimeout(() => {
          resultsRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }, 500);

    } catch (e) {
      console.error(e);
      alert("Failed to generate. Please check your connection.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleGenerateImage = async (post: SocialPost) => {
    if (!post.visualPrompt) return;
    setGeneratingImageForId(post.id);
    try {
        const imageUrl = await generateImage(post.visualPrompt);
        if (imageUrl) {
            setGeneratedPosts(prev => prev.map(p => 
                p.id === post.id ? { ...p, imageUrl } : p
            ));
        } else {
            alert("Failed to generate image. Try again.");
        }
    } catch (e) {
        console.error(e);
        alert("Error generating image.");
    } finally {
        setGeneratingImageForId(null);
    }
  };

  const handleRepurpose = async (originalPost: SocialPost) => {
    setIsRepurposing(true);
    try {
       const newPost = await repurposePost(originalPost, repurposePlatform, repurposeFormat);
       setGeneratedPosts(prev => [newPost, ...prev]);
       setRepurposeTargetId(null); 
    } catch (e) {
       alert("Failed to repurpose.");
    } finally {
       setIsRepurposing(false);
    }
  };

  const handleToggleSelect = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(pid => pid !== id) : [...prev, id]);
  };

  const handleSelectAll = () => {
    if (selectedIds.length === generatedPosts.length) {
      setSelectedIds([]);
    } else {
      setSelectedIds(generatedPosts.map(p => p.id));
    }
  };

  const openScheduleModal = (posts: SocialPost[]) => {
      setPostsToSchedule(posts);
      const tomorrow = new Date();
      tomorrow.setDate(tomorrow.getDate() + 1);
      tomorrow.setHours(9, 0, 0, 0);
      const pad = (n: number) => n.toString().padStart(2, '0');
      const year = tomorrow.getFullYear();
      const month = pad(tomorrow.getMonth() + 1);
      const day = pad(tomorrow.getDate());
      const hour = pad(tomorrow.getHours());
      const minute = pad(tomorrow.getMinutes());
      setScheduleDate(`${year}-${month}-${day}T${hour}:${minute}`);
  };

  const handleSingleAction = (post: SocialPost) => {
    if (post.flaggedKeywords.length > 0) {
      addPost(post);
      setGeneratedPosts(prev => prev.filter(p => p.id !== post.id));
      setSelectedIds(prev => prev.filter(id => id !== post.id));
      alert("Saved to Approvals. This post has some quality flags.");
    } else {
      openScheduleModal([post]);
    }
  };

  const handleSaveDraft = (post: SocialPost) => {
    addPost({ ...post, status: PostStatus.DRAFT });
    setGeneratedPosts(prev => prev.filter(p => p.id !== post.id));
    setSelectedIds(prev => prev.filter(id => id !== post.id));
  };

  const handleBulkSchedule = () => {
    const selected = generatedPosts.filter(p => selectedIds.includes(p.id));
    if (selected.length === 0) return;
    openScheduleModal(selected);
  };

  const handleConfirmSchedule = () => {
    if (postsToSchedule.length === 0) return;
    if (!scheduleDate) {
      alert("Please select a date and time.");
      return;
    }
    const timestamp = new Date(scheduleDate).getTime();
    postsToSchedule.forEach(post => {
        const isFlagged = restrictedTerms.some(term => post.content.toLowerCase().includes(term.toLowerCase()));
        addPost({
            ...post,
            status: PostStatus.SCHEDULED,
            scheduledTime: timestamp
        });
    });

    const scheduledIds = postsToSchedule.map(p => p.id);
    setGeneratedPosts(prev => prev.filter(p => !scheduledIds.includes(p.id)));
    setSelectedIds(prev => prev.filter(id => !scheduledIds.includes(id)));
    setPostsToSchedule([]);
    setScheduleDate('');
  };

  // Visual Helper: Format Icon
  const renderFormatVisual = (id: ContentFormat, isSelected: boolean) => {
    const strokeClass = isSelected ? "stroke-purple-400" : "stroke-slate-500";
    const fillClass = isSelected ? "fill-purple-400" : "fill-slate-500";
    const bgClass = isSelected ? "bg-purple-500/20" : "bg-slate-800";
    const borderClass = isSelected ? "border-purple-500" : "border-slate-700";
    const textClass = isSelected ? "bg-purple-400" : "bg-slate-600";

    switch(id) {
        case 'Post':
            return (
                <div className={clsx("w-10 h-10 border-2 rounded-md flex flex-col p-1 gap-1", borderClass, bgClass)}>
                    <div className={clsx("w-full h-5 rounded-sm opacity-50", textClass)}></div>
                    <div className={clsx("w-full h-0.5 rounded-full", textClass)}></div>
                    <div className={clsx("w-2/3 h-0.5 rounded-full", textClass)}></div>
                </div>
            );
        case 'Story':
            return (
                <div className={clsx("w-8 h-12 border-2 rounded-lg flex flex-col items-center p-1 gap-1", borderClass, bgClass)}>
                     <div className={clsx("w-2 h-0.5 rounded-full mb-0.5", textClass)}></div>
                     <div className={clsx("w-full h-full rounded-sm opacity-30", textClass)}></div>
                </div>
            );
        case 'Reel':
            return (
                <div className={clsx("w-8 h-12 border-2 rounded-lg flex items-center justify-center relative", borderClass, bgClass)}>
                    <Play className={clsx("w-4 h-4 ml-0.5", fillClass)} />
                    <div className={clsx("absolute bottom-1 w-4 h-0.5 rounded-full opacity-50", textClass)}></div>
                </div>
            );
         case 'Video':
            return (
                <div className={clsx("w-14 h-9 border-2 rounded-md flex items-center justify-center", borderClass, bgClass)}>
                    <Play className={clsx("w-5 h-5 ml-0.5", fillClass)} />
                </div>
            );
         case 'Carousel':
            return (
                <div className="relative w-10 h-10 flex items-center justify-center">
                    <div className={clsx("absolute w-8 h-10 border-2 rounded-md transform -rotate-6 -translate-x-1", isSelected ? "border-purple-500/40 bg-purple-500/10" : "border-slate-700 bg-slate-800")}></div>
                    <div className={clsx("absolute w-8 h-10 border-2 rounded-md transform rotate-6 translate-x-1 z-10", borderClass, bgClass)}></div>
                </div>
            );
         case 'Thread':
             return (
                 <div className="flex flex-col items-center gap-1">
                     <div className={clsx("w-10 h-4 border-2 rounded-full", borderClass, bgClass)}></div>
                     <div className={clsx("w-0.5 h-1.5", textClass)}></div>
                     <div className={clsx("w-10 h-4 border-2 rounded-full opacity-70", borderClass, bgClass)}></div>
                 </div>
             );
    }
  }

  const getRecommendedFormats = (platform: Platform): ContentFormat[] => {
      switch(platform) {
          case 'Instagram': return ['Reel', 'Story', 'Carousel'];
          case 'TikTok': return ['Reel'];
          case 'YouTube': return ['Video', 'Reel'];
          case 'LinkedIn': return ['Post', 'Carousel'];
          case 'Twitter': return ['Post', 'Thread'];
          case 'Pinterest': return ['Post'];
          case 'Facebook': return ['Post', 'Reel', 'Story'];
          case 'Threads': return ['Thread', 'Post'];
          default: return ['Post'];
      }
  };

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col space-y-6 relative">

      {/* Scheduling Modal */}
      {postsToSchedule.length > 0 && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4 animate-in fade-in zoom-in duration-200">
           <div className="bg-slate-950 border border-slate-700 rounded-xl p-6 w-full max-w-md shadow-2xl max-h-[90vh] overflow-y-auto">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold text-white flex items-center gap-2">
                  <Calendar className="w-5 h-5 text-blue-500" />
                  Schedule {postsToSchedule.length} Post{postsToSchedule.length > 1 ? 's' : ''}
                </h3>
                <button onClick={() => setPostsToSchedule([])} className="text-slate-400 hover:text-white"><X className="w-5 h-5" /></button>
              </div>
              <div className="mb-6">
                <input type="datetime-local" className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-600 focus:outline-none" value={scheduleDate} onChange={(e) => setScheduleDate(e.target.value)} />
              </div>
              <div className="flex justify-end gap-3">
                <button onClick={() => setPostsToSchedule([])} className="px-4 py-2 text-slate-400 hover:text-white">Cancel</button>
                <button onClick={handleConfirmSchedule} className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-bold">Confirm</button>
              </div>
           </div>
        </div>
      )}

      {/* Repurpose Modal */}
      {repurposeTargetId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4 animate-in fade-in zoom-in duration-200">
           <div className="bg-slate-950 border border-slate-700 rounded-xl p-6 w-full max-w-3xl shadow-2xl max-h-[90vh] overflow-y-auto">
              <div className="flex justify-between items-center mb-6">
                 <h3 className="text-xl font-bold text-white">Repurpose Content</h3>
                 <button onClick={() => setRepurposeTargetId(null)} className="text-slate-400"><X className="w-5 h-5" /></button>
              </div>

              <div className="grid md:grid-cols-2 gap-8 mb-6">
                 <div>
                    <h4 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-2">Original Post</h4>
                    <div className="bg-slate-900 p-4 rounded-lg border border-slate-800 text-slate-300 text-sm italic">
                        "{generatedPosts.find(p => p.id === repurposeTargetId)?.content}"
                    </div>
                 </div>

                 <div>
                    <h4 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-2">Target Platform</h4>
                    <div className="space-y-4">
                        <div className="grid grid-cols-3 gap-2">
                            {PLATFORMS.slice(0, 9).map(p => {
                                const originalPost = generatedPosts.find(post => post.id === repurposeTargetId);
                                const isRec = originalPost && (() => {
                                    const map: Record<string, string[]> = {
                                        'Twitter': ['LinkedIn', 'Instagram', 'Threads'],
                                        'LinkedIn': ['Twitter', 'Facebook', 'Instagram'],
                                        'Instagram': ['TikTok', 'Facebook', 'Pinterest'],
                                        'TikTok': ['Instagram', 'YouTube'],
                                        'Facebook': ['Instagram', 'LinkedIn'],
                                        'YouTube': ['TikTok', 'Instagram'],
                                    };
                                    return map[originalPost.platform]?.includes(p.id);
                                })();
                                const Icon = p.icon;

                                return (
                                    <button
                                        key={p.id}
                                        onClick={() => {
                                            setRepurposePlatform(p.id);
                                            const rec = getRecommendedFormats(p.id);
                                            setRepurposeFormat(rec[0]);
                                        }}
                                        className={clsx(
                                            "flex flex-col items-center justify-center p-3 rounded-lg border text-xs font-bold transition-all relative overflow-visible gap-1.5",
                                            repurposePlatform === p.id 
                                            ? "bg-blue-600 border-blue-500 text-white" 
                                            : "bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-600"
                                        )}
                                    >
                                        {isRec && (
                                            <span className="absolute -top-2 -right-2 z-20 bg-emerald-500 text-slate-900 text-[9px] px-1.5 py-0.5 rounded-full font-bold shadow-sm flex items-center gap-0.5 border border-emerald-400">
                                                <Star className="w-2 h-2 fill-current" /> Best
                                            </span>
                                        )}
                                        {Icon && <Icon className={clsx("w-5 h-5", repurposePlatform === p.id ? "text-white" : p.color)} />}
                                        {p.id}
                                    </button>
                                );
                            })}
                        </div>

                        <div>
                            <h4 className="text-xs font-bold text-slate-500 mb-2">Format</h4>
                            <div className="flex gap-2">
                                {getRecommendedFormats(repurposePlatform).map((fmt, idx) => {
                                    const originalPost = generatedPosts.find(post => post.id === repurposeTargetId);
                                    const isRec = originalPost && (() => {
                                        const sFmt = originalPost.format || 'Post';
                                        // Video -> Video
                                        if (['Reel', 'Video'].includes(sFmt) && ['Reel', 'Video'].includes(fmt)) return true;
                                        // Text -> Text/Image adaptation
                                        if (sFmt === 'Post' && (fmt === 'Post' || fmt === 'Story')) return true;
                                        if (sFmt === 'Thread' && (fmt === 'Carousel' || fmt === 'Post')) return true;
                                        if (sFmt === 'Carousel' && fmt === 'Carousel') return true;
                                        // Fallback default
                                        return idx === 0;
                                    })();

                                    return (
                                        <button
                                            key={fmt}
                                            onClick={() => setRepurposeFormat(fmt)}
                                            className={clsx(
                                                "px-3 py-1.5 rounded-full text-xs font-bold border transition-all flex items-center",
                                                repurposeFormat === fmt
                                                ? "bg-purple-600 border-purple-500 text-white"
                                                : "bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-600"
                                            )}
                                        >
                                            {fmt}
                                            {isRec && <span className="ml-1.5 bg-emerald-500/20 text-emerald-400 text-[9px] px-1.5 py-0.5 rounded-full uppercase tracking-wider">Rec</span>}
                                        </button>
                                    );
                                })}
                            </div>
                        </div>
                    </div>
                 </div>
              </div>

              <div className="flex justify-end gap-3 pt-6 border-t border-slate-800">
                 <button onClick={() => setRepurposeTargetId(null)} className="px-5 py-2.5 text-slate-400 hover:text-white transition-colors">Cancel</button>
                 <button onClick={() => handleRepurpose(generatedPosts.find(p => p.id === repurposeTargetId)!)} disabled={isRepurposing} className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-2.5 rounded-lg font-bold transition-all flex items-center gap-2">
                    {isRepurposing ? <Loader2 className="w-4 h-4 animate-spin" /> : <RefreshCw className="w-4 h-4" />}
                    Generate Remix
                 </button>
              </div>
           </div>
        </div>
      )}

      <div className="flex justify-between items-center shrink-0">
        <div>
           <h2 className="text-2xl md:text-3xl font-bold text-white">Create Post</h2>
           <p className="text-slate-400 text-sm md:text-base">Turn a simple idea into posts for all your channels.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 h-full min-h-0">
        {/* Left Config Panel */}
        <div className="lg:col-span-4 h-full overflow-y-auto pr-2 pb-10 scrollbar-hide">
          <div className="bg-slate-950 border border-slate-800 rounded-xl p-5 shadow-sm">
             <div className="mb-6">
                <label className="block text-sm font-bold text-slate-200 mb-3 flex items-center gap-2">
                    <Lightbulb className="w-4 h-4 text-yellow-400" /> What do you want to post about?
                </label>

                {/* Categorized Idea Starters */}
                <div className="space-y-2 mb-4">
                    {Object.entries(CATEGORIZED_IDEAS).map(([category, ideas]) => (
                        <div key={category} className="flex flex-wrap gap-2">
                            <span className="text-[10px] font-bold text-slate-500 uppercase tracking-wider w-full">{category}</span>
                            {ideas.map(idea => (
                                <button 
                                    key={idea} 
                                    onClick={() => setCoreMessage(prev => prev ? prev + " " + idea : idea)}
                                    className="text-[10px] bg-slate-900 hover:bg-slate-800 border border-slate-800 hover:border-slate-600 text-slate-300 px-3 py-1.5 rounded-lg transition-colors shadow-sm"
                                >
                                    {idea}
                                </button>
                            ))}
                        </div>
                    ))}
                </div>

                <div className="relative group">
                    <textarea
                    className="w-full h-32 bg-slate-900 border border-slate-800 rounded-xl p-4 text-white focus:ring-2 focus:ring-blue-600 focus:outline-none resize-none placeholder-slate-600 text-sm leading-relaxed pr-10"
                    placeholder="e.g. We have a special on croissants this weekend! Buy one get one free. #weekendvibes"
                    value={coreMessage}
                    onChange={(e) => setCoreMessage(e.target.value)}
                    />
                    <button 
                        onClick={handleEnhancePrompt}
                        disabled={!coreMessage}
                        className="absolute bottom-3 right-3 p-1.5 text-purple-400 hover:text-white bg-slate-800 hover:bg-purple-600 rounded-lg transition-colors disabled:opacity-0 disabled:pointer-events-none"
                        title="Magic Enhance Prompt"
                    >
                        <Wand2 className="w-4 h-4" />
                    </button>
                </div>
             </div>

             <div className="mb-6">
                <div className="flex justify-between items-center mb-3">
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider">Target Platforms</label>
                    <button 
                        onClick={handleSelectAllPlatforms}
                        className="text-[10px] text-blue-400 hover:text-blue-300 font-bold uppercase tracking-wider flex items-center gap-1 bg-blue-900/10 px-2 py-1 rounded hover:bg-blue-900/20"
                    >
                        <Layers className="w-3 h-3" />
                        {selectedPlatforms.length === PLATFORMS.length ? 'Deselect All' : 'Post to All Channels'}
                    </button>
                </div>
                <div className="grid grid-cols-3 gap-2">
                   {PLATFORMS.map(p => {
                      const Icon = p.icon;
                      const isSelected = selectedPlatforms.includes(p.id);
                      return (
                        <button
                          key={p.id}
                          onClick={() => togglePlatform(p.id)}
                          className={clsx(
                             "flex flex-col items-center justify-center p-2 rounded-xl border-2 transition-all gap-1 h-20 group relative overflow-hidden",
                             isSelected 
                               ? `bg-slate-800 border-blue-500 shadow-[0_0_15px_rgba(59,130,246,0.3)] z-10 scale-[1.02]` 
                               : "bg-slate-900 border-slate-800 opacity-70 hover:opacity-100 hover:border-slate-600"
                          )}
                          title={p.label}
                        >
                           {isSelected && <div className="absolute inset-0 bg-blue-600/5 pointer-events-none"></div>}
                           {isSelected && <div className="absolute top-1 right-1"><CheckCircle className="w-3 h-3 text-blue-500" /></div>}
                           {Icon && <Icon className={clsx("w-6 h-6 transition-transform group-hover:scale-110", isSelected ? p.color : "text-slate-400")} />}
                           <span className={clsx("text-[10px] font-bold text-center leading-tight", isSelected ? "text-white" : "text-slate-500")}>
                               {p.label.split('(')[0]}
                           </span>
                        </button>
                      );
                   })}
                </div>
             </div>

             <div className="mb-6">
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Post Type</label>
                <div className="grid grid-cols-2 gap-3">
                   {FORMATS.map(f => {
                      const isSelected = selectedFormat === f.id;
                      return (
                        <button 
                            key={f.id}
                            onClick={() => setSelectedFormat(f.id)}
                            className={clsx(
                                "relative flex flex-col items-center justify-center p-3 rounded-xl border-2 transition-all gap-2 h-24 text-center group",
                                isSelected 
                                ? "bg-purple-900/20 border-purple-500 text-white shadow-lg shadow-purple-900/20 scale-[1.02]" 
                                : "bg-slate-900 border-slate-800 text-slate-400 hover:border-slate-600 hover:bg-slate-800"
                            )}
                        >
                            {/* Selection Indicator Dot */}
                            {isSelected && (
                                <div className="absolute top-2 right-2 w-2 h-2 bg-purple-500 rounded-full shadow-[0_0_8px_rgba(168,85,247,0.8)]"></div>
                            )}

                            <div className={clsx("shrink-0 transition-transform group-hover:scale-110 duration-300")}>
                                {renderFormatVisual(f.id, isSelected)}
                            </div>
                            <span className={clsx("text-xs font-bold uppercase tracking-wider", isSelected ? "text-white" : "text-slate-500")}>{f.label}</span>
                        </button>
                      );
                   })}
                </div>
             </div>

             <button
                onClick={handleGenerate}
                disabled={isGenerating || !coreMessage}
                className="w-full bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 disabled:from-slate-800 disabled:to-slate-800 disabled:text-slate-500 text-white px-6 py-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all shadow-lg shadow-blue-900/20 text-lg hover:scale-[1.02] active:scale-95"
               >
                 {isGenerating ? <Loader2 className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5" />}
                 Generate Posts
             </button>
          </div>
        </div>

        {/* Results Panel */}
        <div className="lg:col-span-8 space-y-4 h-full overflow-y-auto pb-20 pr-2 scrollbar-hide" ref={resultsRef}>
          {generatedPosts.length === 0 && !isGenerating && (
            <div className="h-full flex flex-col items-center justify-center text-slate-600 border-2 border-dashed border-slate-800 rounded-xl min-h-[400px] bg-slate-900/20">
              <div className="relative mb-6">
                 <div className="absolute inset-0 bg-blue-500/20 rounded-full blur-xl animate-pulse"></div>
                 <div className="p-6 bg-slate-900 rounded-full relative z-10 border border-slate-800">
                    <Sparkles className="w-10 h-10 text-blue-500" />
                 </div>
              </div>
              <h3 className="text-xl font-bold text-white mb-2">Ready to create magic?</h3>
              <p className="text-sm text-slate-400 max-w-xs text-center leading-relaxed">Select your target platforms on the left, type a quick idea, and hit Generate to see the AI in action.</p>
            </div>
          )}

          {isGenerating && (
            <div className="space-y-4">
              {[1, 2].map(i => (
                <div key={i} className="animate-pulse bg-slate-950 border border-slate-800 rounded-xl p-6 h-64 flex flex-col justify-between">
                    <div className="flex gap-4">
                        <div className="w-12 h-12 bg-slate-800 rounded-full"></div>
                        <div className="space-y-2 flex-1">
                            <div className="h-4 bg-slate-800 rounded w-1/4"></div>
                            <div className="h-3 bg-slate-800 rounded w-1/6"></div>
                        </div>
                    </div>
                    <div className="space-y-2 mt-4">
                        <div className="h-3 bg-slate-800 rounded w-full"></div>
                        <div className="h-3 bg-slate-800 rounded w-full"></div>
                        <div className="h-3 bg-slate-800 rounded w-2/3"></div>
                    </div>
                    <div className="h-32 bg-slate-800 rounded mt-4"></div>
                </div>
              ))}
            </div>
          )}

          {generatedPosts.length > 0 && (
             <div className="flex items-center justify-between bg-slate-900/80 border border-slate-800 rounded-xl p-4 sticky top-0 z-20 backdrop-blur-md shadow-lg">
                <div className="flex items-center gap-3">
                    <input 
                        type="checkbox"
                        checked={selectedIds.length > 0 && selectedIds.length === generatedPosts.length}
                        onChange={handleSelectAll}
                        className="w-5 h-5 rounded border-slate-700 bg-slate-950 text-blue-600 focus:ring-blue-500 cursor-pointer"
                    />
                    <span className="text-sm font-bold text-slate-200">
                        {selectedIds.length > 0 ? `${selectedIds.length} Selected` : 'Select All'}
                    </span>
                </div>
                {selectedIds.length > 0 && (
                    <button 
                        onClick={handleBulkSchedule}
                        className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2 rounded-lg text-sm font-bold transition-all flex items-center gap-2 shadow-lg shadow-blue-900/20 active:scale-95"
                    >
                        <Calendar className="w-4 h-4" />
                        Schedule ({selectedIds.length})
                    </button>
                )}
             </div>
          )}

          {generatedPosts.map((post) => {
            const PlatformIcon = PLATFORMS.find(p => p.id === post.platform)?.icon;
            const platformColor = PLATFORMS.find(p => p.id === post.platform)?.color || 'text-slate-400';

            return (
            <div key={post.id} className="bg-slate-950 border border-slate-800 rounded-xl p-6 group hover:border-slate-700 transition-all relative shadow-sm">

              {/* Header Bar */}
              <div className="flex justify-between items-start mb-4">
                <div className="flex items-center gap-4">
                   <div className="relative">
                        <input 
                            type="checkbox"
                            checked={selectedIds.includes(post.id)}
                            onChange={() => handleToggleSelect(post.id)}
                            className="w-5 h-5 rounded border-slate-700 bg-slate-900 text-blue-600 focus:ring-blue-500 cursor-pointer z-10 relative"
                        />
                   </div>
                   <div className="flex items-center gap-2">
                        <div className={`p-1.5 rounded-lg bg-slate-900 border border-slate-800 ${platformColor}`}>
                            {PlatformIcon && <PlatformIcon className="w-4 h-4" />}
                        </div>
                        <div>
                            <p className="text-sm font-bold text-white leading-none">{post.platform}</p>
                            <p className="text-[10px] text-slate-500 font-medium uppercase tracking-wider mt-0.5">{post.format || 'Post'}</p>
                        </div>
                   </div>
                </div>

                <div className="flex items-center gap-3">
                    <span className={`text-xs font-bold px-2 py-1 rounded-md bg-slate-900 border border-slate-800 ${post.voiceScore > 80 ? 'text-emerald-400 border-emerald-900/30' : 'text-amber-400 border-amber-900/30'}`}>
                        {post.voiceScore}% Voice Score
                    </span>
                    <button 
                       onClick={() => setRepurposeTargetId(post.id)}
                       className="text-xs bg-slate-900 hover:bg-slate-800 border border-slate-800 hover:border-slate-700 text-slate-400 hover:text-white px-3 py-1.5 rounded-md transition-all flex items-center gap-1.5 font-medium"
                    >
                       <RefreshCw className="w-3 h-3" /> Remix
                    </button>
                </div>
              </div>

              {/* Social Preview Container */}
              <div className="bg-slate-900 rounded-xl border border-slate-800 p-5 relative overflow-hidden mb-4 group/preview transition-all hover:border-slate-700">
                 {/* Mock Social Header */}
                 <div className="flex items-center gap-3 mb-4 opacity-80">
                    <div className="w-10 h-10 rounded-full bg-gradient-to-br from-blue-500 to-purple-600 flex items-center justify-center text-white text-xs font-bold">
                        {currentUser?.name.charAt(0) || 'U'}
                    </div>
                    <div>
                        <p className="text-sm font-bold text-white leading-tight">{currentUser?.name || 'Your Brand'}</p>
                        <p className="text-xs text-slate-500">@{currentUser?.companyName.replace(/\s+/g, '').toLowerCase() || 'brandhandle'}</p>
                    </div>
                    <div className="ml-auto text-slate-600">
                        <MoreHorizontal className="w-5 h-5" />
                    </div>
                 </div>

                 {/* Editable Content */}
                 <textarea 
                    className="w-full bg-transparent text-slate-200 text-sm mb-4 leading-relaxed whitespace-pre-wrap font-normal focus:outline-none resize-none rounded transition-colors border border-transparent focus:border-slate-700/50 p-1 -ml-1 placeholder-slate-600"
                    rows={post.imageUrl ? 3 : 6}
                    value={post.content}
                    onChange={(e) => handleUpdatePost(post.id, 'content', e.target.value)}
                    placeholder="Write your caption here..."
                 />

                 {/* Visual Media */}
                 <div className="space-y-4">
                    {post.imageUrl ? (
                        <div className="relative group/image">
                            <img src={post.imageUrl} alt="AI Generated" className="w-full h-64 object-cover rounded-lg border border-slate-800" />
                            <div className="absolute bottom-2 right-2 flex gap-2 opacity-0 group-hover/image:opacity-100 transition-opacity">
                                <button 
                                    onClick={() => handleGenerateImage(post)}
                                    disabled={generatingImageForId === post.id}
                                    className="bg-black/70 hover:bg-black text-white text-xs px-3 py-1.5 rounded-full backdrop-blur-sm flex items-center gap-1.5 transition-all"
                                >
                                    {generatingImageForId === post.id ? <Loader2 className="w-3 h-3 animate-spin" /> : <RefreshCw className="w-3 h-3" />}
                                    Regenerate Art
                                </button>
                            </div>
                        </div>
                    ) : (
                        <div className="bg-slate-950/50 border border-slate-800 rounded-lg p-3 relative overflow-hidden group/visual hover:bg-slate-950 transition-colors">
                            <div className="flex items-center gap-2 mb-2 relative z-10">
                                <ImageIcon className="w-4 h-4 text-purple-400" />
                                <span className="text-xs font-bold text-purple-300">AI Visual Prompt</span>
                            </div>
                            <div className="relative z-10 flex gap-2">
                                <textarea 
                                    className="w-full bg-transparent text-xs text-slate-400 italic leading-relaxed resize-none focus:outline-none focus:text-slate-300 transition-colors"
                                    value={post.visualPrompt || ''}
                                    onChange={(e) => handleUpdatePost(post.id, 'visualPrompt', e.target.value)}
                                    rows={2}
                                    placeholder="Describe the image you want..."
                                />
                                {post.visualPrompt && (
                                    <button
                                        onClick={() => handleGenerateImage(post)}
                                        disabled={generatingImageForId === post.id}
                                        className="self-end p-2 bg-purple-600 hover:bg-purple-500 text-white rounded-lg shadow-lg transition-colors disabled:opacity-50 shrink-0"
                                        title="Generate Image"
                                    >
                                        {generatingImageForId === post.id ? <Loader2 className="w-4 h-4 animate-spin" /> : <Wand2 className="w-4 h-4" />}
                                    </button>
                                )}
                            </div>
                        </div>
                    )}
                 </div>

                 {/* Mock Interaction Bar */}
                 <div className="mt-4 pt-3 border-t border-slate-800 flex items-center justify-between text-slate-500">
                    <div className="flex gap-4">
                        <Heart className="w-5 h-5 hover:text-pink-500 cursor-pointer transition-colors" />
                        <MessageCircle className="w-5 h-5 hover:text-blue-400 cursor-pointer transition-colors" />
                        <Share2 className="w-5 h-5 hover:text-emerald-400 cursor-pointer transition-colors" />
                    </div>
                    <div className="text-xs font-medium opacity-50">Preview Mode</div>
                 </div>
              </div>

              {/* Warnings */}
              {post.flaggedKeywords.length > 0 && (
                <div className="mb-4 p-3 bg-amber-950/30 border border-amber-900/50 rounded-lg flex items-start gap-3">
                    <AlertTriangle className="w-4 h-4 text-amber-500 shrink-0 mt-0.5" />
                    <div>
                        <p className="text-xs font-bold text-amber-400 mb-0.5">Content Quality Check</p>
                        <p className="text-[10px] text-amber-200/70">
                        Contains flagged terms: <span className="font-mono text-amber-200">{post.flaggedKeywords.join(', ')}</span>
                        </p>
                    </div>
                </div>
              )}

              {/* Action Footer */}
              <div className="flex flex-wrap justify-end gap-3 pt-2">
                <button onClick={() => navigator.clipboard.writeText(post.content)} className="p-2 text-slate-500 hover:text-white transition-colors hover:bg-slate-900 rounded-lg" title="Copy text"><Copy className="w-5 h-5" /></button>
                <button onClick={() => handleSaveDraft(post)} className="bg-slate-900 border border-slate-800 hover:bg-slate-800 hover:border-slate-700 text-slate-300 px-4 py-2 rounded-lg text-sm font-bold transition-all flex items-center gap-2"><Save className="w-4 h-4" /> Draft</button>
                <button onClick={() => handleSingleAction(post)} className="bg-blue-600 hover:bg-blue-500 text-white px-5 py-2 rounded-lg text-sm font-bold transition-all shadow-lg shadow-blue-900/20 flex items-center gap-2"><Calendar className="w-4 h-4" /> Schedule</button>
              </div>
            </div>
          );
          })}
        </div>
      </div>
    </div>
  );
};

export default ContentStudio;

import React, { useState, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import { SocialPost, PostStatus, ContentFormat, Platform } from '../types';
import { Sparkles, AlertTriangle, CheckCircle, Copy, Loader2, Calendar, X, Instagram, Facebook, Linkedin, Twitter, Youtube, RefreshCw, Image as ImageIcon, Save, Wand2, Pin, MapPin, Ghost, Hash, Video, AtSign, FileText, Smartphone, Film, MonitorPlay, GalleryHorizontal, ListTree, Layers, Lightbulb, Play, Star, Heart, MessageCircle, Share2, MoreHorizontal, ArrowRight } from 'lucide-react';
import clsx from 'clsx';

const PLATFORMS: { id: Platform; label: string; icon: any; color: string; bg: string }[] = [
  { id: 'Facebook', label: 'Facebook', icon: Facebook, color: 'text-blue-500', bg: 'bg-blue-500' },
  { id: 'Instagram', label: 'Instagram', icon: Instagram, color: 'text-pink-500', bg: 'bg-pink-500' },
  { id: 'LinkedIn', label: 'LinkedIn', icon: Linkedin, color: 'text-blue-700', bg: 'bg-blue-700' },
  { id: 'Twitter', label: 'Twitter (X)', icon: Twitter, color: 'text-sky-500', bg: 'bg-sky-500' },
  { id: 'TikTok', label: 'TikTok', icon: Video, color: 'text-teal-400', bg: 'bg-teal-400' },
  { id: 'YouTube', label: 'YouTube', icon: Youtube, color: 'text-red-600', bg: 'bg-red-600' },
  { id: 'Pinterest', label: 'Pinterest', icon: Pin, color: 'text-red-500', bg: 'bg-red-500' },
  { id: 'Google Business', label: 'Google Business', icon: MapPin, color: 'text-blue-500', bg: 'bg-blue-500' },
  { id: 'Snapchat', label: 'Snapchat', icon: Ghost, color: 'text-yellow-400', bg: 'bg-yellow-400' },
  { id: 'Reddit', label: 'Reddit', icon: Hash, color: 'text-orange-500', bg: 'bg-orange-500' },
  { id: 'Threads', label: 'Threads', icon: AtSign, color: 'text-slate-200', bg: 'bg-slate-200' },
];

const FORMATS: { id: ContentFormat; label: string; icon: any; desc: string }[] = [
  { id: 'Post', label: 'Standard Post', icon: FileText, desc: 'Text & Image' },
  { id: 'Story', label: 'Story', icon: Smartphone, desc: 'Vertical Update' },
  { id: 'Reel', label: 'Reel / Short', icon: Film, desc: 'Short Video Script' },
  { id: 'Video', label: 'Video Script', icon: MonitorPlay, desc: 'Long Form' },
  { id: 'Carousel', label: 'Carousel', icon: GalleryHorizontal, desc: 'Multi-slide' },
  { id: 'Thread', label: 'Thread', icon: ListTree, desc: 'Twitter/Threads' },
];

const CATEGORIZED_IDEAS = {
    "Promote": ["🎉 Product Launch", "⚡ Flash Sale", "🎁 Giveaway"],
    "Educate": ["💡 Expert Tip", "📚 How-To Guide", "🧠 Industry Insight"],
    "Engage": ["❓ Question", "🗳️ Poll", "👋 Behind the Scenes"]
};

const ContentStudio: React.FC = () => {
  const { generateContent, repurposePost, generateImage, addPost, restrictedTerms, currentUser } = useApp();
  const location = useLocation();
  const resultsRef = useRef<HTMLDivElement>(null);

  const [coreMessage, setCoreMessage] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedPosts, setGeneratedPosts] = useState<SocialPost[]>([]);

  // Generation Settings
  const [selectedPlatforms, setSelectedPlatforms] = useState<Platform[]>(['Instagram', 'LinkedIn', 'Twitter', 'Facebook']);
  const [selectedFormat, setSelectedFormat] = useState<ContentFormat>('Post');

  // Selection & Scheduling State
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [postsToSchedule, setPostsToSchedule] = useState<SocialPost[]>([]);
  const [scheduleDate, setScheduleDate] = useState('');

  // Repurpose State
  const [repurposeTargetId, setRepurposeTargetId] = useState<string | null>(null);
  const [repurposePlatform, setRepurposePlatform] = useState<Platform>('Instagram');
  const [repurposeFormat, setRepurposeFormat] = useState<ContentFormat>('Story');
  const [isRepurposing, setIsRepurposing] = useState(false);

  // Image Gen State
  const [generatingImageForId, setGeneratingImageForId] = useState<string | null>(null);

  // Handle incoming data
  useEffect(() => {
    if (location.state) {
      const { coreMessage, platforms, format } = location.state as any;
      if (coreMessage) setCoreMessage(coreMessage);
      if (platforms) setSelectedPlatforms(platforms);
      if (format) setSelectedFormat(format);
      window.history.replaceState({}, document.title);
    }
  }, [location.state]);

  const togglePlatform = (p: Platform) => {
    setSelectedPlatforms(prev => 
      prev.includes(p) ? prev.filter(x => x !== p) : [...prev, p]
    );
  };

  const handleSelectAllPlatforms = () => {
    if (selectedPlatforms.length === PLATFORMS.length) {
        setSelectedPlatforms([]);
    } else {
        setSelectedPlatforms(PLATFORMS.map(p => p.id));
    }
  };

  const handleUpdatePost = (id: string, field: keyof SocialPost, value: any) => {
    setGeneratedPosts(prev => prev.map(p => 
      p.id === id ? { ...p, [field]: value } : p
    ));
  };

  const handleEnhancePrompt = () => {
      if(!coreMessage) return;
      setCoreMessage(prev => prev + " (Make it engaging, professional, and viral-worthy)");
  };

  const handleGenerate = async () => {
    if (!coreMessage.trim()) return;
    if (selectedPlatforms.length === 0) {
      alert("Please select at least one platform (e.g. Facebook).");
      return;
    }
    setIsGenerating(true);
    setSelectedIds([]);
    try {
      const posts = await generateContent(coreMessage, { platforms: selectedPlatforms, format: selectedFormat });
      setGeneratedPosts(posts);

      // Auto-scroll to results on mobile/desktop
      setTimeout(() => {
          resultsRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }, 500);

    } catch (e) {
      console.error(e);
      alert("Failed to generate. Please check your connection.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleGenerateImage = async (post: SocialPost) => {
    if (!post.visualPrompt) return;
    setGeneratingImageForId(post.id);
    try {
        const imageUrl = await generateImage(post.visualPrompt);
        if (imageUrl) {
            setGeneratedPosts(prev => prev.map(p => 
                p.id === post.id ? { ...p, imageUrl } : p
            ));
        } else {
            alert("Failed to generate image. Try again.");
        }
    } catch (e) {
        console.error(e);
        alert("Error generating image.");
    } finally {
        setGeneratingImageForId(null);
    }
  };

  const handleRepurpose = async (originalPost: SocialPost) => {
    setIsRepurposing(true);
    try {
       const newPost = await repurposePost(originalPost, repurposePlatform, repurposeFormat);
       setGeneratedPosts(prev => [newPost, ...prev]);
       setRepurposeTargetId(null); 
    } catch (e) {
       alert("Failed to repurpose.");
    } finally {
       setIsRepurposing(false);
    }
  };

  const handleToggleSelect = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(pid => pid !== id) : [...prev, id]);
  };

  const handleSelectAll = () => {
    if (selectedIds.length === generatedPosts.length) {
      setSelectedIds([]);
    } else {
      setSelectedIds(generatedPosts.map(p => p.id));
    }
  };

  const openScheduleModal = (posts: SocialPost[]) => {
      setPostsToSchedule(posts);
      const tomorrow = new Date();
      tomorrow.setDate(tomorrow.getDate() + 1);
      tomorrow.setHours(9, 0, 0, 0);
      const pad = (n: number) => n.toString().padStart(2, '0');
      const year = tomorrow.getFullYear();
      const month = pad(tomorrow.getMonth() + 1);
      const day = pad(tomorrow.getDate());
      const hour = pad(tomorrow.getHours());
      const minute = pad(tomorrow.getMinutes());
      setScheduleDate(`${year}-${month}-${day}T${hour}:${minute}`);
  };

  const handleSingleAction = (post: SocialPost) => {
    if (post.flaggedKeywords.length > 0) {
      addPost(post);
      setGeneratedPosts(prev => prev.filter(p => p.id !== post.id));
      setSelectedIds(prev => prev.filter(id => id !== post.id));
      alert("Saved to Approvals. This post has some quality flags.");
    } else {
      openScheduleModal([post]);
    }
  };

  const handleSaveDraft = (post: SocialPost) => {
    addPost({ ...post, status: PostStatus.DRAFT });
    setGeneratedPosts(prev => prev.filter(p => p.id !== post.id));
    setSelectedIds(prev => prev.filter(id => id !== post.id));
  };

  const handleBulkSchedule = () => {
    const selected = generatedPosts.filter(p => selectedIds.includes(p.id));
    if (selected.length === 0) return;
    openScheduleModal(selected);
  };

  const handleConfirmSchedule = () => {
    if (postsToSchedule.length === 0) return;
    if (!scheduleDate) {
      alert("Please select a date and time.");
      return;
    }
    const timestamp = new Date(scheduleDate).getTime();
    postsToSchedule.forEach(post => {
        const isFlagged = restrictedTerms.some(term => post.content.toLowerCase().includes(term.toLowerCase()));
        addPost({
            ...post,
            status: PostStatus.SCHEDULED,
            scheduledTime: timestamp
        });
    });

    const scheduledIds = postsToSchedule.map(p => p.id);
    setGeneratedPosts(prev => prev.filter(p => !scheduledIds.includes(p.id)));
    setSelectedIds(prev => prev.filter(id => !scheduledIds.includes(id)));
    setPostsToSchedule([]);
    setScheduleDate('');
  };

  const getRecommendedFormats = (platform: Platform): ContentFormat[] => {
      switch(platform) {
          case 'Instagram': return ['Reel', 'Story', 'Carousel'];
          case 'TikTok': return ['Reel'];
          case 'YouTube': return ['Video', 'Reel'];
          case 'LinkedIn': return ['Post', 'Carousel'];
          case 'Twitter': return ['Post', 'Thread'];
          case 'Pinterest': return ['Post'];
          case 'Facebook': return ['Post', 'Reel', 'Story'];
          case 'Threads': return ['Thread', 'Post'];
          default: return ['Post'];
      }
  };

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col space-y-6 relative">

      {/* Scheduling Modal */}
      {postsToSchedule.length > 0 && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4 animate-in fade-in zoom-in duration-200">
           <div className="bg-slate-950 border border-slate-700 rounded-xl p-6 w-full max-w-md shadow-2xl max-h-[90vh] overflow-y-auto">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold text-white flex items-center gap-2">
                  <Calendar className="w-5 h-5 text-blue-500" />
                  Schedule {postsToSchedule.length} Post{postsToSchedule.length > 1 ? 's' : ''}
                </h3>
                <button onClick={() => setPostsToSchedule([])} className="text-slate-400 hover:text-white"><X className="w-5 h-5" /></button>
              </div>
              <div className="mb-6">
                <input type="datetime-local" className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-600 focus:outline-none" value={scheduleDate} onChange={(e) => setScheduleDate(e.target.value)} />
              </div>
              <div className="flex justify-end gap-3">
                <button onClick={() => setPostsToSchedule([])} className="px-4 py-2 text-slate-400 hover:text-white">Cancel</button>
                <button onClick={handleConfirmSchedule} className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-bold">Confirm</button>
              </div>
           </div>
        </div>
      )}

      {/* Repurpose Modal */}
      {repurposeTargetId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4 animate-in fade-in zoom-in duration-200">
           <div className="bg-slate-950 border border-slate-700 rounded-xl p-6 w-full max-w-3xl shadow-2xl max-h-[90vh] overflow-y-auto">
              <div className="flex justify-between items-center mb-6">
                 <h3 className="text-xl font-bold text-white">Repurpose Content</h3>
                 <button onClick={() => setRepurposeTargetId(null)} className="text-slate-400"><X className="w-5 h-5" /></button>
              </div>

              <div className="grid md:grid-cols-2 gap-8 mb-6">
                 <div>
                    <h4 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-2">Original Post</h4>
                    <div className="bg-slate-900 p-4 rounded-lg border border-slate-800 text-slate-300 text-sm italic">
                        "{generatedPosts.find(p => p.id === repurposeTargetId)?.content}"
                    </div>
                 </div>

                 <div>
                    <h4 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-2">Target Platform</h4>
                    <div className="space-y-4">
                        <div className="grid grid-cols-3 gap-2">
                            {PLATFORMS.slice(0, 9).map(p => {
                                const originalPost = generatedPosts.find(post => post.id === repurposeTargetId);
                                const isRec = originalPost && (() => {
                                    const map: Record<string, string[]> = {
                                        'Twitter': ['LinkedIn', 'Instagram', 'Threads'],
                                        'LinkedIn': ['Twitter', 'Facebook', 'Instagram'],
                                        'Instagram': ['TikTok', 'Facebook', 'Pinterest'],
                                        'TikTok': ['Instagram', 'YouTube'],
                                        'Facebook': ['Instagram', 'LinkedIn'],
                                        'YouTube': ['TikTok', 'Instagram'],
                                    };
                                    return map[originalPost.platform]?.includes(p.id);
                                })();
                                const Icon = p.icon;

                                return (
                                    <button
                                        key={p.id}
                                        onClick={() => {
                                            setRepurposePlatform(p.id);
                                            const rec = getRecommendedFormats(p.id);
                                            setRepurposeFormat(rec[0]);
                                        }}
                                        className={clsx(
                                            "flex flex-col items-center justify-center p-3 rounded-lg border text-xs font-bold transition-all relative overflow-visible gap-1.5",
                                            repurposePlatform === p.id 
                                            ? "bg-blue-600 border-blue-500 text-white" 
                                            : "bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-600"
                                        )}
                                    >
                                        {isRec && (
                                            <span className="absolute -top-2 -right-2 z-20 bg-emerald-500 text-slate-900 text-[9px] px-1.5 py-0.5 rounded-full font-bold shadow-sm flex items-center gap-0.5 border border-emerald-400">
                                                <Star className="w-2 h-2 fill-current" /> Best
                                            </span>
                                        )}
                                        {Icon && <Icon className={clsx("w-5 h-5", repurposePlatform === p.id ? "text-white" : p.color)} />}
                                        {p.id}
                                    </button>
                                );
                            })}
                        </div>

                        <div>
                            <h4 className="text-xs font-bold text-slate-500 mb-2">Format</h4>
                            <div className="flex gap-2">
                                {getRecommendedFormats(repurposePlatform).map((fmt, idx) => {
                                    return (
                                        <button
                                            key={fmt}
                                            onClick={() => setRepurposeFormat(fmt)}
                                            className={clsx(
                                                "px-3 py-1.5 rounded-full text-xs font-bold border transition-all flex items-center",
                                                repurposeFormat === fmt
                                                ? "bg-purple-600 border-purple-500 text-white"
                                                : "bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-600"
                                            )}
                                        >
                                            {fmt}
                                        </button>
                                    );
                                })}
                            </div>
                        </div>
                    </div>
                 </div>
              </div>

              <div className="flex justify-end gap-3 pt-6 border-t border-slate-800">
                 <button onClick={() => setRepurposeTargetId(null)} className="px-5 py-2.5 text-slate-400 hover:text-white transition-colors">Cancel</button>
                 <button onClick={() => handleRepurpose(generatedPosts.find(p => p.id === repurposeTargetId)!)} disabled={isRepurposing} className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-2.5 rounded-lg font-bold transition-all flex items-center gap-2">
                    {isRepurposing ? <Loader2 className="w-4 h-4 animate-spin" /> : <RefreshCw className="w-4 h-4" />}
                    Generate Remix
                 </button>
              </div>
           </div>
        </div>
      )}

      <div className="flex justify-between items-center shrink-0">
        <div>
