              </div>

              {/* Warnings */}
              {post.flaggedKeywords.length > 0 && (
                <div className="mb-4 p-3 bg-amber-950/30 border border-amber-900/50 rounded-lg flex items-start gap-3">
                    <AlertTriangle className="w-4 h-4 text-amber-500 shrink-0 mt-0.5" />
                    <div>
                        <p className="text-xs font-bold text-amber-400 mb-0.5">Content Quality Check</p>
                        <p className="text-[10px] text-amber-200/70">
                        Contains flagged terms: <span className="font-mono text-amber-200">{post.flaggedKeywords.join(', ')}</span>
