              )}

              {/* Action Footer */}
              <div className="flex flex-wrap justify-end gap-3 pt-2">
                <button onClick={() => navigator.clipboard.writeText(post.content)} className="p-2 text-slate-500 hover:text-white transition-colors hover:bg-slate-900 rounded-lg" title="Copy text"><Copy className="w-5 h-5" /></button>
                <button onClick={() => handleSaveDraft(post)} className="bg-slate-900 border border-slate-800 hover:bg-slate-800 hover:border-slate-700 text-slate-300 px-4 py-2 rounded-lg text-sm font-bold transition-all flex items-center gap-2"><Save className="w-4 h-4" /> Draft</button>
                <button onClick={() => handleSingleAction(post)} className="bg-blue-600 hover:bg-blue-500 text-white px-5 py-2 rounded-lg text-sm font-bold transition-all shadow-lg shadow-blue-900/20 flex items-center gap-2 hover:scale-105 active:scale-95"><Calendar className="w-4 h-4" /> Schedule</button>
