                    rows={post.imageUrl ? 3 : 6}
                    value={post.content}
                    onChange={(e) => handleUpdatePost(post.id, 'content', e.target.value)}
                    placeholder="Write your caption here..."
                 />

                 {/* Visual Media */}
                 <div className="space-y-4">
                    {post.imageUrl ? (
                        <div className="relative group/image">
                            <img src={post.imageUrl} alt="AI Generated" className="w-full h-72 object-cover rounded-lg border border-slate-800 shadow-sm" />
                            <div className="absolute bottom-3 right-3 flex gap-2 opacity-0 group-hover/image:opacity-100 transition-opacity">
                                <button 
                                    onClick={() => handleGenerateImage(post)}
                                    disabled={generatingImageForId === post.id}
                                    className="bg-black/70 hover:bg-black text-white text-xs px-3 py-1.5 rounded-full backdrop-blur-sm flex items-center gap-1.5 transition-all font-bold border border-white/10"
                                >
                                    {generatingImageForId === post.id ? <Loader2 className="w-3 h-3 animate-spin" /> : <RefreshCw className="w-3 h-3" />}
                                    Regenerate Art
                                </button>
                            </div>
                        </div>
                    ) : (
                        <div className="bg-slate-950/50 border border-slate-800 rounded-lg p-4 relative overflow-hidden group/visual hover:bg-slate-950 transition-colors">
                            <div className="flex items-center gap-2 mb-2 relative z-10">
                                <ImageIcon className="w-4 h-4 text-purple-400" />
                                <span className="text-xs font-bold text-purple-300">AI Visual Concept</span>
                            </div>
                            <div className="relative z-10 flex gap-2">
                                <textarea 
                                    className="w-full bg-transparent text-xs text-slate-400 italic leading-relaxed resize-none focus:outline-none focus:text-slate-300 transition-colors"
                                    value={post.visualPrompt || ''}
                                    onChange={(e) => handleUpdatePost(post.id, 'visualPrompt', e.target.value)}
                                    rows={2}
                                    placeholder="Describe the image you want..."
                                />
                                {post.visualPrompt && (
                                    <button
                                        onClick={() => handleGenerateImage(post)}
                                        disabled={generatingImageForId === post.id}
                                        className="self-end p-2 bg-purple-600 hover:bg-purple-500 text-white rounded-lg shadow-lg transition-colors disabled:opacity-50 shrink-0"
                                        title="Generate Image"
                                    >
                                        {generatingImageForId === post.id ? <Loader2 className="w-4 h-4 animate-spin" /> : <Wand2 className="w-4 h-4" />}
                                    </button>
                                )}
                            </div>
                        </div>
                    )}
                 </div>

                 {/* Mock Interaction Bar */}
                 <div className="mt-4 pt-3 border-t border-slate-800 flex items-center justify-between text-slate-500">
                    <div className="flex gap-4">
                        <Heart className="w-5 h-5 hover:text-pink-500 cursor-pointer transition-colors" />
                        <MessageCircle className="w-5 h-5 hover:text-blue-400 cursor-pointer transition-colors" />
                        <Share2 className="w-5 h-5 hover:text-emerald-400 cursor-pointer transition-colors" />
                    </div>
                    <div className="text-xs font-medium opacity-50 flex items-center gap-1">
                        <ArrowRight className="w-3 h-3" /> Preview
                    </div>
                 </div>
              </div>

              {/* Warnings */}
              {post.flaggedKeywords.length > 0 && (
                <div className="mb-4 p-3 bg-amber-950/30 border border-amber-900/50 rounded-lg flex items-start gap-3">
                    <AlertTriangle className="w-4 h-4 text-amber-500 shrink-0 mt-0.5" />
                    <div>
                        <p className="text-xs font-bold text-amber-400 mb-0.5">Content Quality Check</p>
                        <p className="text-[10px] text-amber-200/70">
                        Contains flagged terms: <span className="font-mono text-amber-200">{post.flaggedKeywords.join(', ')}</span>
                        </p>
                    </div>
                </div>
              )}

              {/* Action Footer */}
              <div className="flex flex-wrap justify-end gap-3 pt-2">
                <button onClick={() => navigator.clipboard.writeText(post.content)} className="p-2 text-slate-500 hover:text-white transition-colors hover:bg-slate-900 rounded-lg" title="Copy text"><Copy className="w-5 h-5" /></button>
                <button onClick={() => handleSaveDraft(post)} className="bg-slate-900 border border-slate-800 hover:bg-slate-800 hover:border-slate-700 text-slate-300 px-4 py-2 rounded-lg text-sm font-bold transition-all flex items-center gap-2"><Save className="w-4 h-4" /> Draft</button>
                <button onClick={() => handleSingleAction(post)} className="bg-blue-600 hover:bg-blue-500 text-white px-5 py-2 rounded-lg text-sm font-bold transition-all shadow-lg shadow-blue-900/20 flex items-center gap-2 hover:scale-105 active:scale-95"><Calendar className="w-4 h-4" /> Schedule</button>
              </div>
            </div>
          );
          })}
        </div>
      </div>
    </div>
  );
};

export default ContentStudio;

