const getMockSocialContent = (
  coreMessage: string, 
  platforms: string[], 
  format: ContentFormat, 
  voiceSettings: BrandVoiceSettings
) => {
  return platforms.map(p => {
    let content = "";
    let visualPrompt = "";
    const baseScore = Math.floor(Math.random() * (99 - 88) + 88);

    if (format === 'Carousel') {
      content = `🎨 SLIDE 1: Title\n"${coreMessage}"\n\n👉 SLIDE 2: The Problem\nMany people struggle with this specific issue because...\n\n💡 SLIDE 3: The Solution\nHere is the fix: We use a proprietary method to ensure quality.\n\n✅ SLIDE 4: The Result\nLook at these benefits! consistent results every time.\n\n👋 SLIDE 5: Call to Action\nSave this post for later reference!`;
      visualPrompt = "A minimalist, geometric set of slide backgrounds using brand colors. Clean typography, modern aesthetic, Gamma app style presentation.";
    } else if (format === 'Reel') {
      content = `🎬 SCENE 1 (0:00-0:03)\nVisual: Fast cut of the product in use.\nAudio: Trending upbeat pop track.\nText Overlay: "You need to try this!"\n\n🎬 SCENE 2 (0:03-0:10)\nVisual: Demo of the feature in action, close up.\nAudio: Voiceover explaining the benefit clearly.\n\n🎬 SCENE 3 (0:10-0:15)\nVisual: Happy customer smiling or dancing.\nCaption: Link in bio to shop!`;
      visualPrompt = "A cinematic storyboard frame of a happy customer holding the product, warm lighting, 4k resolution, bokeh effect.";
    } else if (format === 'Thread') {
      content = `1/5 ${coreMessage}\n\n2/5 Here is the first key point you need to know. It changes how you think about [Topic]. 🧵\n\n3/5 Another important detail is consistency. Without it, results vary.\n\n4/5 Don't forget this crucial step: Always measure your impact.\n\n5/5 Thanks for reading! Follow for more tips like this. #Growth`;
