export const chatWithOnboardingAgent = async (
    userMessage: string,
    history: ChatMessage[],
    userContext: { name: string; plan: string }
): Promise<string> => {
    if (!process.env.API_KEY) {
        return "I am running in demo mode without an API key, but I'd love to help you explore Zentaras!";
    }

    const systemInstruction = `
    You are Zen, the friendly AI Onboarding Specialist for "Zentaras", an AI Marketing Operating System.

    USER CONTEXT:
    Name: ${userContext.name}
    Plan: ${userContext.plan}

    APP FEATURES KNOWLEDGE BASE:
    - **TrendHunter**: Located in the sidebar. Helps users find viral topics and newsjacks them.
    - **Content Studio**: The main place to create posts for 11+ platforms. Supports repurposing.
    - **Campaigns**: Creates full 30-day content calendars based on a single goal.
    - **Monitor**: Analytics dashboard to track performance and brand mentions.
    - **Inbox**: Unified community management for replying to comments/DMs.
    - **Settings**: Where users configure their "Brand Voice" and connect integrations.

    YOUR GOAL:
    Help the user get started. Keep answers concise, encouraging, and helpful. 
    If they ask how to do something, give them the specific steps or point them to the right page.
    Use emojis to be friendly.
    `;

    try {
        // Convert history to Gemini format (limiting context window for efficiency)
        const recentHistory = history.slice(-6).map(msg => ({
            role: msg.role === 'user' ? 'user' : 'model',
            parts: [{ text: msg.text }]
        }));

        const aiInstance = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const chat = aiInstance.chats.create({
            model: FAST_MODEL,
            config: {
                systemInstruction: systemInstruction,
                temperature: 0.7,
            },
            history: recentHistory
        });

        const result = await chat.sendMessage({ message: userMessage });
        return result.text || "I'm having a little trouble thinking right now. Try again?";
    } catch (error) {
        console.error("Onboarding Chat Error:", error);
        return "I'm having trouble connecting to my brain at the moment. Please try again later.";
    }
};

export const generateCampaignPlan = async (
  goal: string,
  durationDays: number,
  platforms: string[],
  trainingData?: { website: string; sampleContent: string },
  targetAudience?: string
): Promise<CampaignPostTemplate[]> => {

  if (!process.env.API_KEY) {
    return getMockCampaignPlan(durationDays, platforms);
  }

  const prompt = `
    You are a Senior Marketing Strategist Agent.
    Create a content calendar strategy for a campaign.

    CONTEXT ANALYSIS (TRAINING DATA):
    - Website Context: ${trainingData?.website || "N/A"}
    - Top Performing Content Patterns: "${trainingData?.sampleContent || "N/A"}"
    *Analyze the style, structure, and hooks of the top performing content. Replicate these success patterns in the strategy.*

    CAMPAIGN DETAILS:
    - GOAL: "${goal}"
    - TARGET AUDIENCE: "${targetAudience || "General Audience"}"
    - DURATION: ${durationDays} days
    - AVAILABLE PLATFORMS: ${platforms.join(', ')}

    INSTRUCTIONS:
    1. Create a sequence of 4-6 high-impact posts spread across the duration.
    2. Vary the formats (Post, Story, Carousel, Reel) based on what works best for the intent and the target audience.
    3. Ensure a narrative arc: Tease -> Launch -> Educate/Proof -> Close.
    4. Adapt the "Intent" to fit the analyzed brand style and audience preferences.

    Output pure JSON array.
  `;

  const schema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        dayOffset: { type: Type.INTEGER, description: "Day number starting from 0" },
        platform: { type: Type.STRING },
        format: { type: Type.STRING },
        intent: { type: Type.STRING, description: "The purpose of this post (e.g. Teaser)" }
      },
      required: ["dayOffset", "platform", "format", "intent"]
    }
  };

  try {
    const response = await ai.models.generateContent({
      model: FAST_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
      },
    });
    const cleanedText = cleanJsonResponse(response.text || '[]');
    return JSON.parse(cleanedText);
  } catch (error: any) {
    if (error.status === 429 || error.code === 429) {
        console.warn("Gemini Quota Exceeded (Campaign Plan). Using fallback strategy.");
    } else {
        console.error("Gemini Campaign Plan Error:", error);
    }
    // Fallback to basic plan
    return getMockCampaignPlan(durationDays, platforms);
  }
};

export const generateSocialContent = async (
  coreMessage: string,
  platforms: string[],
  format: ContentFormat,
  voiceSettings: BrandVoiceSettings
): Promise<any[]> => {

  if (!process.env.API_KEY) {
    return getMockSocialContent(coreMessage, platforms, format, voiceSettings);
  }

  const prompt = `
    You are an expert social media content creator akin to a top-tier marketing agency.

    TOPIC: "${coreMessage}"
    BRAND VOICE: "${voiceSettings.description}" (Target Score: ${voiceSettings.targetScore})
    TONE LEVEL: ${voiceSettings.tone}/100 (0=Corporate/Serious, 100=Playful/Meme-friendly)
    TARGET PLATFORMS: ${platforms.join(', ')}
    CONTENT FORMAT: ${format}

    INSTRUCTIONS:
    1. Generate content for each selected platform in the requested format.
    2. STRUCTURE IS KEY. Use the following templates:
       - 'Carousel': Use "Slide 1: [Title] - [Body]" format. Make it educational and visually structured (like a Gamma.app presentation).
       - 'Reel': Use "Scene 1 (Time): [Visual] - [Audio]" format. (TikTok/Reels script style).
       - 'Thread': Use "1/X [Text]" format. (Twitter/Threads style).
       - 'Video': Use "Scene/Timecode" format for longer video scripts.
       - 'Story': Text Overlay + Visual description.
       - 'Post': Engaging caption with line breaks and hashtags.
    3. Visuals (Nano Banana Style): Provide a 'visualPrompt' that is highly descriptive, artistic, and style-specific. 
       - Use terms like "Photorealistic," "Cinematic lighting," "Vector art," "Pastel flat lay," or "Cyberpunk" depending on the vibe. 
       - The prompt should be ready for a high-end image generator.
    4. Score: Calculate Voice Score (0-100).

    Output pure JSON.
  `;

  const schema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        platform: { type: Type.STRING },
        content: { type: Type.STRING },
        voiceScore: { type: Type.INTEGER },
        predictedEngagement: { type: Type.STRING },
        visualPrompt: { type: Type.STRING, description: "Detailed prompt for AI image generation (Nano Banana style)" }
      },
      required: ["platform", "content", "voiceScore", "predictedEngagement", "visualPrompt"]
    }
  };

  try {
    const response = await ai.models.generateContent({
      model: FAST_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
        temperature: 0.8, // Increased for creativity
      },
    });

    const cleanedText = cleanJsonResponse(response.text || '[]');
    return JSON.parse(cleanedText);
  } catch (error: any) {
    if (error.status === 429 || error.code === 429) {
        console.warn("Gemini Quota Exceeded (Content Gen). Using mock content.");
    } else {
        console.error("Gemini Generation Error:", error);
    }
    // Return high-quality mock content on error
    return getMockSocialContent(coreMessage, platforms, format, voiceSettings);
  }
};

export const generateImage = async (prompt: string): Promise<string | null> => {
  if (!process.env.API_KEY) {
    return getMockImage(prompt);
  }

  try {
    const response = await ai.models.generateContent({
      model: IMAGE_MODEL,
      contents: {
        parts: [
          { text: prompt }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return getMockImage(prompt);
  } catch (error: any) {
    console.warn("Gemini Image Gen Error (likely quota or permission). Using fallback.", error.message);
    return getMockImage(prompt);
  }
};

export const analyzeIncomingMessage = async (
  message: string
): Promise<Partial<IncomingMessage>> => {
  const fallback = {
    sentiment: 'Neutral' as const,
    riskLevel: 'Low' as const,
    suggestedReply: "Thanks for reaching out! We'll be with you shortly."
  };

  if (!process.env.API_KEY) {
     return fallback;
  }

  const prompt = `
    You are a customer service assistant.
    Analyze this message: "${message}"

    1. Sentiment: Positive, Neutral, Negative, or Sarcastic.
    2. Risk Level: 
       - High (Angry customer, refund request, harassment)
       - Low (Question, compliment, mild feedback)
    3. Suggested Reply: Polite, helpful, short. If High risk, suggest asking them to DM or email support.
  `;

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      sentiment: { type: Type.STRING, enum: ["Positive", "Neutral", "Negative", "Sarcastic"] },
      riskLevel: { type: Type.STRING, enum: ["Low", "High"] },
      suggestedReply: { type: Type.STRING }
    },
    required: ["sentiment", "riskLevel", "suggestedReply"]
  };

  try {
    const response = await ai.models.generateContent({
      model: FAST_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
      },
    });

    const cleanedText = cleanJsonResponse(response.text || '{}');
    return JSON.parse(cleanedText);
  } catch (error: any) {
    if (error.status === 429 || error.code === 429) {
        console.warn("Gemini Quota Exceeded (Sentiment). Using mock analysis.");
    } else {
        console.error("Gemini Sentiment Error:", error);
    }
    return fallback;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { useApp } from '../context/AppContext';
import { chatWithOnboardingAgent } from '../services/geminiService';
import { ChatMessage } from '../types';
import { Bot, Send, X, MessageCircle, Sparkles, User, Loader2, ChevronDown } from 'lucide-react';
import clsx from 'clsx';

const OnboardingAssistant: React.FC = () => {
    const { currentUser } = useApp();
    const [isOpen, setIsOpen] = useState(false);
    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [inputValue, setInputValue] = useState('');
    const [isTyping, setIsTyping] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    // Initial Greeting
    useEffect(() => {
        if (currentUser && messages.length === 0) {
            setMessages([
                {
                    id: 'init-1',
                    role: 'assistant',
                    text: `Hi ${currentUser.name.split(' ')[0]}! 👋 I'm Zen, your personal onboarding assistant.`,
                    timestamp: Date.now()
                },
                {
                    id: 'init-2',
                    role: 'assistant',
                    text: "I can help you set up your brand voice, create your first campaign, or explain any feature. What would you like to do first?",
                    timestamp: Date.now() + 100
                }
            ]);
        }
    }, [currentUser]);

    // Auto-scroll to bottom
    useEffect(() => {
        if (isOpen) {
            messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
        }
    }, [messages, isOpen]);

    const handleSendMessage = async () => {
        if (!inputValue.trim() || !currentUser) return;

        const userMsg: ChatMessage = {
            id: `msg-${Date.now()}`,
            role: 'user',
            text: inputValue,
            timestamp: Date.now()
        };

        setMessages(prev => [...prev, userMsg]);
        setInputValue('');
        setIsTyping(true);

        try {
            const responseText = await chatWithOnboardingAgent(
                userMsg.text, 
                messages, 
                { name: currentUser.name, plan: currentUser.plan }
            );

            const aiMsg: ChatMessage = {
                id: `resp-${Date.now()}`,
                role: 'assistant',
                text: responseText,
                timestamp: Date.now()
            };

            setMessages(prev => [...prev, aiMsg]);
        } catch (error) {
            console.error("Chat Error", error);
        } finally {
            setIsTyping(false);
        }
    };

    const handleKeyPress = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            handleSendMessage();
        }
    };

    if (!currentUser) return null;

    return (
        <>
            {/* Floating Trigger Button */}
            <button
                onClick={() => setIsOpen(!isOpen)}
                className={clsx(
                    "fixed bottom-6 right-6 z-50 p-4 rounded-full shadow-2xl transition-all duration-300 hover:scale-110 flex items-center justify-center group",
                    isOpen ? "bg-slate-800 text-slate-400 rotate-90" : "bg-gradient-to-tr from-indigo-600 to-purple-600 text-white"
                )}
            >
                {isOpen ? <X className="w-6 h-6" /> : <Bot className="w-7 h-7" />}
                {!isOpen && (
                    <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full border-2 border-slate-900"></span>
                )}
                {!isOpen && (
                   <div className="absolute right-full mr-4 bg-slate-900 text-white px-3 py-1.5 rounded-lg text-xs font-bold whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none border border-slate-700">
                       Chat with Zen
                   </div>
                )}
            </button>

            {/* Chat Window */}
            <div 
                className={clsx(
                    "fixed bottom-24 right-6 w-[360px] max-w-[calc(100vw-48px)] h-[550px] max-h-[70vh] bg-slate-950 border border-slate-800 rounded-2xl shadow-2xl z-50 flex flex-col overflow-hidden transition-all duration-300 origin-bottom-right",
                    isOpen ? "opacity-100 scale-100" : "opacity-0 scale-95 pointer-events-none translate-y-4"
                )}
            >
                {/* Header */}
                <div className="bg-gradient-to-r from-indigo-900/50 to-purple-900/50 p-4 border-b border-slate-800 flex justify-between items-center backdrop-blur-md">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center shadow-lg border border-white/10">
                            <Bot className="w-6 h-6 text-white" />
                        </div>
                        <div>
                            <h3 className="font-bold text-white text-sm">Zen Assistant</h3>
                            <p className="text-xs text-indigo-300 flex items-center gap-1">
                                <Sparkles className="w-3 h-3" /> AI Onboarding
                            </p>
                        </div>
                    </div>
                    <button onClick={() => setIsOpen(false)} className="text-slate-400 hover:text-white transition-colors">
                        <ChevronDown className="w-5 h-5" />
                    </button>
                </div>

                {/* Messages Area */}
                <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-900/50">
                    {messages.map((msg) => (
                        <div 
                            key={msg.id} 
                            className={clsx(
                                "flex gap-3 max-w-[90%]",
                                msg.role === 'user' ? "ml-auto flex-row-reverse" : "mr-auto"
