    }

    return {
      platform: p,
      content: content,
      voiceScore: baseScore,
      predictedEngagement: "High",
      visualPrompt: visualPrompt
    };
  });
};

const getMockCampaignPlan = (durationDays: number, platforms: string[]): CampaignPostTemplate[] => {
    return [
      { dayOffset: 0, platform: platforms[0] as any, format: 'Post', intent: 'Teaser / Announcement' },
      { dayOffset: 1, platform: platforms[1] || platforms[0] as any, format: 'Story', intent: 'Behind the Scenes / Hype' },
      { dayOffset: Math.floor(durationDays / 2), platform: platforms[0] as any, format: 'Carousel', intent: 'Educational / Value Prop' },
      { dayOffset: durationDays - 1, platform: platforms[0] as any, format: 'Post', intent: 'Last Chance / Call to Action' }
    ];
};

const getMockImage = (prompt: string) => {
    const encodedPrompt = encodeURIComponent(prompt);
    const randomSeed = Math.floor(Math.random() * 10000);
    return `https://image.pollinations.ai/prompt/${encodedPrompt}?nologo=true&seed=${randomSeed}&width=1024&height=1024`;
};

