    "Educate": ["💡 Expert Tip", "📚 How-To Guide", "🧠 Industry Insight"],
    "Engage": ["❓ Question", "🗳️ Poll", "👋 Behind the Scenes"]
};

// AI Thinking Animation Component
const AIThinkingOverlay = ({ isVisible }: { isVisible: boolean }) => {
    const [thought, setThought] = useState("Analyzing Brand Voice...");

    useEffect(() => {
        if (!isVisible) return;
        const thoughts = [
            "Analyzing Brand Voice...",
            "Scanning Trending Hashtags...",
            "Optimizing for Virality...",
            "Generating Visual Concepts...",
            "Formatting for Platform...",
            "Polishing Tone..."
        ];
        let i = 0;
        const interval = setInterval(() => {
            setThought(thoughts[i % thoughts.length]);
            i++;
        }, 800);
        return () => clearInterval(interval);
    }, [isVisible]);

    if (!isVisible) return null;

    return (
        <div className="absolute inset-0 z-50 bg-slate-950/80 backdrop-blur-sm flex flex-col items-center justify-center rounded-xl border border-indigo-500/30">
            <div className="relative">
                <div className="w-24 h-24 rounded-full bg-indigo-500/20 animate-ping absolute inset-0"></div>
                <div className="w-24 h-24 rounded-full bg-gradient-to-tr from-indigo-600 to-purple-600 flex items-center justify-center shadow-[0_0_30px_rgba(99,102,241,0.6)] relative z-10">
                    <Sparkles className="w-10 h-10 text-white animate-pulse" />
                </div>
            </div>
            <div className="mt-8 text-center space-y-2">
                <h3 className="text-xl font-bold text-white tracking-tight animate-pulse">{thought}</h3>
                <p className="text-xs text-indigo-300 font-mono uppercase tracking-widest">Powered by Gemini 2.5</p>
            </div>
        </div>
    );
};

