    return (
        <div className="w-full rounded-lg border border-slate-700 bg-slate-900 shadow-2xl overflow-hidden">
            {/* Browser Header */}
            <div className="h-8 bg-slate-800 border-b border-slate-700 flex items-center px-3 gap-2">
                <div className="flex gap-1.5">
                    <div className="w-2.5 h-2.5 rounded-full bg-red-500/50"></div>
                    <div className="w-2.5 h-2.5 rounded-full bg-yellow-500/50"></div>
                    <div className="w-2.5 h-2.5 rounded-full bg-green-500/50"></div>
                </div>
                <div className="flex-1 mx-4 h-5 bg-slate-900/50 rounded flex items-center justify-center text-[10px] text-slate-500 font-mono">
                    social.network/feed
                </div>
            </div>
            <div className="p-6 min-h-[300px]">
                {children}
