                                    <ImageIcon className="w-4 h-4 text-purple-400" />
                                    <span className="text-xs font-bold text-purple-300">AI Visual Concept</span>
                                </div>
                                <div className="flex gap-2">
                                    <textarea 
                                        className="w-full bg-transparent text-xs text-slate-400 italic leading-relaxed resize-none focus:outline-none focus:text-slate-300 transition-colors"
                                        value={post.visualPrompt || ''}
                                        onChange={(e) => handleUpdatePost(post.id, 'visualPrompt', e.target.value)}
                                        rows={2}
                                        placeholder="Describe the image you want..."
                                    />
                                    {post.visualPrompt && (
                                        <button
                                            onClick={() => handleGenerateImage(post)}
                                            disabled={generatingImageForId === post.id}
