                                            {generatingImageForId === post.id ? <Loader2 className="w-4 h-4 animate-spin" /> : <Wand2 className="w-4 h-4" />}
                                        </button>
                                    )}
                                </div>
                            </div>
                        )}
                     </div>

                     {/* Mock Interaction Bar */}
                     <div className="flex items-center justify-between text-slate-500">
                        <div className="flex gap-4">
                            <Heart className="w-5 h-5 hover:text-pink-500 cursor-pointer transition-colors" />
                            <MessageCircle className="w-5 h-5 hover:text-blue-400 cursor-pointer transition-colors" />
                            <Share2 className="w-5 h-5 hover:text-emerald-400 cursor-pointer transition-colors" />
                        </div>
                     </div>
                 </div>
              </DeviceFrame>

              {/* Warnings & Footer */}
              <div className="mt-4 px-2">
                  {post.flaggedKeywords.length > 0 && (
                    <div className="mb-3 p-2 bg-amber-950/30 border border-amber-900/50 rounded-lg flex items-start gap-2">
                        <AlertTriangle className="w-4 h-4 text-amber-500 shrink-0 mt-0.5" />
                        <p className="text-[10px] text-amber-200/70">
                        Flagged: <span className="font-mono text-amber-200">{post.flaggedKeywords.join(', ')}</span>
                        </p>
                    </div>
                  )}

                  <div className="flex justify-end gap-2">
                    <button onClick={() => navigator.clipboard.writeText(post.content)} className="p-2 text-slate-500 hover:text-white transition-colors hover:bg-slate-900 rounded-lg" title="Copy text"><Copy className="w-4 h-4" /></button>
                    <button onClick={() => handleSaveDraft(post)} className="bg-slate-900 border border-slate-800 hover:bg-slate-800 text-slate-300 px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-2"><Save className="w-3 h-3" /> Draft</button>
                    <button onClick={() => handleSingleAction(post)} className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-1.5 rounded-lg text-xs font-bold transition-all shadow-lg shadow-blue-900/20 flex items-center gap-2"><Calendar className="w-3 h-3" /> Schedule</button>
                  </div>
              </div>
            </div>
          );
          })}
          </div>
        </div>
      </div>
    </div>
  );
};

